INSERT INTO "cache" ("key", "value", "expiration") VALUES ('dobero-home-creator-cache-translations.relocation', 'a:117:{i:0;a:4:{s:3:"key";s:13:"address.h_how";s:2:"en";s:15:"How to register";s:2:"es";s:17:"Cómo registrarse";s:2:"hu";s:23:"A regisztráció menete";}i:1;a:4:{s:3:"key";s:18:"address.h_required";s:2:"en";s:24:"What is it required for?";s:2:"es";s:25:"¿Para qué es necesario?";s:2:"hu";s:17:"Mire szükséges?";}i:2;a:4:{s:3:"key";s:13:"address.how.0";s:2:"en";s:88:"Go to the <strong>town hall (ayuntamiento)</strong> of the municipality where you reside";s:2:"es";s:65:"Acuda al <strong>ayuntamiento</strong> del municipio donde reside";s:2:"hu";s:83:"Menjen a lakhelye szerinti <strong>városháza (ayuntamiento)</strong> épületébe";}i:3;a:4:{s:3:"key";s:13:"address.how.1";s:2:"en";s:42:"Fill out the registration application form";s:2:"es";s:50:"Rellene el impreso de solicitud de empadronamiento";s:2:"hu";s:38:"Töltse ki a regisztrációs kérelmet";}i:4;a:4:{s:3:"key";s:13:"address.how.2";s:2:"en";s:90:"Present your DNI/NIE and passport, plus proof of address (rental contract or utility bill)";s:2:"es";s:116:"Presente su DNI/NIE y pasaporte, junto con justificante de domicilio (contrato de alquiler o factura de suministros)";s:2:"hu";s:114:"Mutassa be DNI/NIE-jét és útlevelét, valamint lakcímigazolást (bérleti szerződés vagy közüzemi számla)";}i:5;a:4:{s:3:"key";s:13:"address.how.3";s:2:"en";s:81:"Receive your registration certificate (certificate can often be requested online)";s:2:"es";s:92:"Reciba el certificado de empadronamiento (en muchos casos puede solicitarse de forma online)";s:2:"hu";s:66:"Vegye át a lakcímigazolást (ez sokszor online is igényelhető)";}i:6;a:4:{s:3:"key";s:13:"address.intro";s:2:"en";s:225:"<strong>Empadronamiento</strong> is the administrative registration of inhabitants in a Spanish municipality — the official registry proving that a person resides in a specific place. It is a municipal (not state) registry.";s:2:"es";s:232:"El <strong>empadronamiento</strong> es el registro administrativo de los habitantes en un municipio español — el registro oficial que acredita que una persona reside en un lugar determinado. Es un registro municipal (no estatal).";s:2:"hu";s:244:"Az <strong>empadronamiento</strong> egy spanyol önkormányzatban lakók adminisztratív nyilvántartása — a hivatalos nyilvántartás, amely igazolja, hogy egy személy egy adott helyen él. Ez önkormányzati (nem állami) nyilvántartás.";}i:7;a:4:{s:3:"key";s:12:"address.note";s:2:"en";s:189:"The registration certificate has no specific expiration date, but some agencies require a recent certificate (less than 3 months old). Always update your registration if you change address.";s:2:"es";s:232:"El certificado de empadronamiento no tiene fecha de caducidad específica, pero algunos organismos requieren un certificado reciente (con menos de 3 meses de antigüedad). Actualice siempre su empadronamiento si cambia de domicilio.";s:2:"hu";s:203:"A lakcímigazolásnak nincs meghatározott lejárati dátuma, de egyes szervek friss igazolást (3 hónaposnál nem régebbit) kérnek. Mindig frissítse bejelentkezését, ha megváltoztatja lakcímét.";}i:8;a:4:{s:3:"key";s:18:"address.required.0";s:2:"en";s:55:"Obtaining a health card — to access public healthcare";s:2:"es";s:67:"Obtener la tarjeta sanitaria — para acceder a la sanidad pública";s:2:"hu";s:74:"Egészségügyi kártya igénylése — a közegészségügy eléréséhez";}i:9;a:4:{s:3:"key";s:18:"address.required.1";s:2:"en";s:43:"Enrolling children in schools or institutes";s:2:"es";s:48:"Escolarizar a los hijos en colegios o institutos";s:2:"hu";s:31:"Gyermekek iskolai beiratkozása";}i:10;a:4:{s:3:"key";s:18:"address.required.2";s:2:"en";s:57:"Applying for social assistance and city council subsidies";s:2:"es";s:52:"Solicitar ayudas sociales y subvenciones municipales";s:2:"hu";s:62:"Szociális segély és önkormányzati támogatás igénylése";}i:11;a:4:{s:3:"key";s:18:"address.required.3";s:2:"en";s:55:"Obtaining or renewing a driving licence (in some cases)";s:2:"es";s:59:"Obtener o renovar el permiso de conducir (en algunos casos)";s:2:"hu";s:65:"Jogosítvány igénylése vagy megújítása (bizonyos esetekben)";}i:12;a:4:{s:3:"key";s:18:"address.required.4";s:2:"en";s:29:"Processing residency in Spain";s:2:"es";s:33:"Tramitar la residencia en España";s:2:"hu";s:40:"Spanyolországi tartózkodás intézése";}i:13;a:4:{s:3:"key";s:18:"address.required.5";s:2:"en";s:29:"Voting in municipal elections";s:2:"es";s:35:"Votar en las elecciones municipales";s:2:"hu";s:44:"Szavazás az önkormányzati választásokon";}i:14;a:4:{s:3:"key";s:18:"address.required.6";s:2:"en";s:59:"A wide variety of other municipal administrative procedures";s:2:"es";s:66:"Una amplia variedad de otros trámites administrativos municipales";s:2:"hu";s:67:"Különféle egyéb önkormányzati adminisztratív ügyintézések";}i:15;a:4:{s:3:"key";s:13:"address.title";s:2:"en";s:38:"Empadronamiento (Address Registration)";s:2:"es";s:15:"Empadronamiento";s:2:"hu";s:36:"Empadronamiento (Lakcímbejelentés)";}i:16;a:4:{s:3:"key";s:16:"bank.h_important";s:2:"en";s:24:"Important things to know";s:2:"es";s:38:"Aspectos importantes a tener en cuenta";s:2:"hu";s:18:"Fontos tudnivalók";}i:17;a:4:{s:3:"key";s:11:"bank.h_uses";s:2:"en";s:44:"What can you do with a Spanish bank account?";s:2:"es";s:53:"¿Qué puede hacer con una cuenta bancaria española?";s:2:"hu";s:38:"Mit tehet egy spanyol bankszámlával?";}i:18;a:4:{s:3:"key";s:16:"bank.important.0";s:2:"en";s:96:"<strong>Required documentation:</strong> NIE, passport or ID card, and possibly proof of address";s:2:"es";s:105:"<strong>Documentación requerida:</strong> NIE, pasaporte o DNI, y posiblemente justificante de domicilio";s:2:"hu";s:114:"<strong>Szükséges dokumentumok:</strong> NIE, útlevél vagy személyi igazolvány, és esetleg lakcímigazolás";}i:19;a:4:{s:3:"key";s:16:"bank.important.1";s:2:"en";s:93:"<strong>Residency requirements:</strong> Some banks may require a minimum period of residence";s:2:"es";s:105:"<strong>Requisitos de residencia:</strong> Algunos bancos pueden exigir un período mínimo de residencia";s:2:"hu";s:104:"<strong>Tartózkodási követelmények:</strong> Egyes bankok minimális tartózkodási időt kérhetnek";}i:20;a:4:{s:3:"key";s:16:"bank.important.2";s:2:"en";s:99:"<strong>Fees:</strong> Compare account maintenance fees, transfer costs, and card fees across banks";s:2:"es";s:111:"<strong>Comisiones:</strong> Compare las comisiones de mantenimiento, transferencias y tarjetas entre entidades";s:2:"hu";s:141:"<strong>Díjak:</strong> Hasonlítsa össze a számlavezetési díjakat, átutalási költségeket és kártyaköltségeket a bankok között";}i:21;a:4:{s:3:"key";s:16:"bank.important.3";s:2:"en";s:73:"<strong>Taxes:</strong> Interest on savings may be subject to Spanish tax";s:2:"es";s:102:"<strong>Impuestos:</strong> Los intereses de los ahorros pueden estar sujetos a tributación española";s:2:"hu";s:92:"<strong>Adók:</strong> A megtakarítások kamatai spanyol adókötelezettség alá eshetnek";}i:22;a:4:{s:3:"key";s:16:"bank.important.4";s:2:"en";s:96:"<strong>Language:</strong> Many banks offer English services; basic Spanish knowledge is helpful";s:2:"es";s:112:"<strong>Idioma:</strong> Muchos bancos ofrecen servicio en inglés; el conocimiento básico de español es útil";s:2:"hu";s:109:"<strong>Nyelv:</strong> Sok bank kínál angol nyelvű szolgáltatást; az alapszintű spanyol tudás hasznos";}i:23;a:4:{s:3:"key";s:10:"bank.intro";s:2:"en";s:174:"A bank account in Spain is essential for foreigners with residency to fully integrate into daily life. It enables a wide range of financial transactions and management tasks.";s:2:"es";s:218:"Una cuenta bancaria en España es imprescindible para que los extranjeros con residencia puedan integrarse plenamente en la vida cotidiana. Permite realizar una amplia variedad de operaciones financieras y de gestión.";s:2:"hu";s:254:"A spanyolországi bankszámla elengedhetetlen a tartózkodási engedéllyel rendelkező külföldiek számára a mindennapi életbe való teljes beilleszkedéshez. Széles körű pénzügyi tranzakciók és ügyintézések elvégzését teszi lehetővé.";}i:24;a:4:{s:3:"key";s:10:"bank.title";s:2:"en";s:20:"Opening Bank Account";s:2:"es";s:27:"Apertura de Cuenta Bancaria";s:2:"hu";s:19:"Bankszámla nyitás";}i:25;a:4:{s:3:"key";s:11:"bank.uses.0";s:2:"en";s:46:"Receive your salary directly into your account";s:2:"es";s:44:"Recibir su nómina directamente en su cuenta";s:2:"hu";s:55:"Fizetésének közvetlen átutaltatása a számlájára";}i:26;a:4:{s:3:"key";s:11:"bank.uses.1";s:2:"en";s:40:"Pay taxes — both national and regional";s:2:"es";s:54:"Pagar impuestos — tanto nacionales como autonómicos";s:2:"hu";s:62:"Adók befizetése — mind országos, mind regionális szinten";}i:27;a:4:{s:3:"key";s:11:"bank.uses.2";s:2:"en";s:59:"Pay utility bills (electricity, water, gas, internet, rent)";s:2:"es";s:64:"Pagar facturas de servicios (luz, agua, gas, internet, alquiler)";s:2:"hu";s:77:"Közüzemi számlák fizetése (villany, víz, gáz, internet, bérleti díj)";}i:28;a:4:{s:3:"key";s:11:"bank.uses.3";s:2:"en";s:28:"Make online purchases safely";s:2:"es";s:39:"Realizar compras online de forma segura";s:2:"hu";s:31:"Biztonságos online vásárlás";}i:29;a:4:{s:3:"key";s:11:"bank.uses.4";s:2:"en";s:54:"Receive international transfers from family or friends";s:2:"es";s:61:"Recibir transferencias internacionales de familiares o amigos";s:2:"hu";s:66:"Nemzetközi utalások fogadása családtagoktól vagy barátoktól";}i:30;a:4:{s:3:"key";s:11:"bank.uses.5";s:2:"en";s:39:"Manage savings and investments in Spain";s:2:"es";s:42:"Gestionar ahorros e inversiones en España";s:2:"hu";s:62:"Megtakarítások és befektetések kezelése Spanyolországban";}i:31;a:4:{s:3:"key";s:11:"bank.uses.6";s:2:"en";s:46:"Receive social benefits you may be entitled to";s:2:"es";s:59:"Recibir prestaciones sociales a las que pueda tener derecho";s:2:"hu";s:42:"Járandó szociális juttatások fogadása";}i:32;a:4:{s:3:"key";s:11:"bank.uses.7";s:2:"en";s:49:"Use debit and credit cards at ATMs and businesses";s:2:"es";s:58:"Usar tarjetas de débito y crédito en cajeros y comercios";s:2:"hu";s:67:"Bankkártya és hitelkártya használata ATM-eknél és üzletekben";}i:33;a:4:{s:3:"key";s:11:"bank.uses.8";s:2:"en";s:57:"Pay with Bizum — Spain''s quick peer-to-peer payment app";s:2:"es";s:81:"Pagar con Bizum — la aplicación española de pagos rápidos entre particulares";s:2:"hu";s:90:"Fizetés Bizummal — Spanyolország gyors személyek közötti fizetési alkalmazásával";}i:34;a:4:{s:3:"key";s:11:"description";s:2:"en";s:65:"Your step-by-step guide to settling in Spain on the Costa Blanca.";s:2:"es";s:67:"Tu guía paso a paso para instalarte en España en la Costa Blanca.";s:2:"hu";s:83:"Lépésről lépésre útmutató a spanyolországi, Costa Blanca-i letelepedéshez.";}i:35;a:4:{s:3:"key";s:27:"digital_signature.h_managed";s:2:"en";s:15:"Who manages it?";s:2:"es";s:21:"¿Quién la gestiona?";s:2:"hu";s:10:"Ki kezeli?";}i:36;a:4:{s:3:"key";s:26:"digital_signature.h_stored";s:2:"en";s:19:"Where is it stored?";s:2:"es";s:21:"¿Dónde se almacena?";s:2:"hu";s:15:"Hol tárolják?";}i:37;a:4:{s:3:"key";s:24:"digital_signature.h_uses";s:2:"en";s:11:"Common uses";s:2:"es";s:15:"Usos habituales";s:2:"hu";s:39:"Leggyakoribb felhasználási területek";}i:38;a:4:{s:3:"key";s:23:"digital_signature.intro";s:2:"en";s:305:"A <strong>digital signature</strong> guarantees the authenticity, integrity, and non-repudiation of an electronic document. It confirms the document has not been altered and was signed by the claimed person. Unlike a scanned handwritten signature, it provides much higher security and full legal validity.";s:2:"es";s:319:"Una <strong>firma digital</strong> garantiza la autenticidad, integridad e irrenunciabilidad de un documento electrónico. Confirma que el documento no ha sido alterado y que fue firmado por la persona identificada. A diferencia de una firma manuscrita escaneada, ofrece una seguridad mucho mayor y plena validez legal.";s:2:"hu";s:373:"A <strong>digitális aláírás</strong> garantálja az elektronikus dokumentum hitelességét, integritását és letagadhatatlanságát. Megerősíti, hogy a dokumentumot nem módosították, és azt az azonosított személy írta alá. A beszkennelt kézzel írott aláírástól eltérően jóval magasabb biztonságot és teljes körű jogi érvényességet biztosít.";}i:39;a:4:{s:3:"key";s:25:"digital_signature.managed";s:2:"en";s:159:"The user is responsible for protecting their private key. A Certification Authority (CA) issues and manages the certificate but does not store the private key.";s:2:"es";s:160:"El usuario es responsable de proteger su clave privada. Una Autoridad de Certificación (CA) emite y gestiona el certificado, pero no almacena la clave privada.";s:2:"hu";s:163:"A felhasználó felelős a privát kulcsa védelméért. A Hitelesítő Hatóság (CA) kiállítja és kezeli a tanúsítványt, de nem tárolja a privát kulcsot.";}i:40;a:4:{s:3:"key";s:22:"digital_signature.note";s:2:"en";s:187:"Digital signatures ensure secure and legally valid electronic transactions in Spain. Handle your certificate responsibly — losing your private key may require reissuing the certificate.";s:2:"es";s:230:"Las firmas digitales garantizan transacciones electrónicas seguras y legalmente válidas en España. Gestione su certificado con responsabilidad — la pérdida de su clave privada puede requerir la reexpedición del certificado.";s:2:"hu";s:252:"A digitális aláírások biztonságos és jogilag érvényes elektronikus tranzakciókat tesznek lehetővé Spanyolországban. Kezelje felelősséggel a tanúsítványát — a privát kulcs elvesztése esetén újra kell igényelni a tanúsítványt.";}i:41;a:4:{s:3:"key";s:26:"digital_signature.stored.0";s:2:"en";s:74:"<strong>Hardware token (USB or smart card)</strong> — most secure option";s:2:"es";s:86:"<strong>Token de hardware (USB o tarjeta inteligente)</strong> — opción más segura";s:2:"hu";s:98:"<strong>Hardveres token (USB vagy intelligens kártya)</strong> — a legbiztonságosabb megoldás";}i:42;a:4:{s:3:"key";s:26:"digital_signature.stored.1";s:2:"en";s:82:"<strong>Certificate software on a computer</strong> — convenient but less secure";s:2:"es";s:86:"<strong>Software de certificado en el ordenador</strong> — cómodo pero menos seguro";s:2:"hu";s:100:"<strong>Tanúsítványszoftver a számítógépen</strong> — kényelmes, de kevésbé biztonságos";}i:43;a:4:{s:3:"key";s:23:"digital_signature.title";s:2:"en";s:17:"Digital Signature";s:2:"es";s:13:"Firma Digital";s:2:"hu";s:21:"Digitális aláírás";}i:44;a:4:{s:3:"key";s:24:"digital_signature.uses.0";s:2:"en";s:24:"Signing online contracts";s:2:"es";s:25:"Firma de contratos online";s:2:"hu";s:32:"Online szerződések aláírása";}i:45;a:4:{s:3:"key";s:24:"digital_signature.uses.1";s:2:"en";s:67:"Filing tax returns with the Spanish Tax Agency (Agencia Tributaria)";s:2:"es";s:70:"Presentación de declaraciones de impuestos ante la Agencia Tributaria";s:2:"hu";s:75:"Adóbevallások benyújtása a spanyol Adóhivatalnál (Agencia Tributaria)";}i:46;a:4:{s:3:"key";s:24:"digital_signature.uses.2";s:2:"en";s:41:"Signing official administrative documents";s:2:"es";s:45:"Firma de documentos administrativos oficiales";s:2:"hu";s:50:"Hivatalos adminisztratív dokumentumok aláírása";}i:47;a:4:{s:3:"key";s:24:"digital_signature.uses.3";s:2:"en";s:34:"Authorizing financial transactions";s:2:"es";s:42:"Autorización de transacciones financieras";s:2:"hu";s:38:"Pénzügyi tranzakciók jóváhagyása";}i:48;a:4:{s:3:"key";s:24:"digital_signature.uses.4";s:2:"en";s:34:"Securing electronic communications";s:2:"es";s:43:"Protección de comunicaciones electrónicas";s:2:"hu";s:36:"Elektronikus kommunikáció védelme";}i:49;a:4:{s:3:"key";s:24:"digital_signature.uses.5";s:2:"en";s:35:"Accessing secure government systems";s:2:"es";s:41:"Acceso a sistemas gubernamentales seguros";s:2:"hu";s:59:"Biztonságos kormányzati rendszerekhez való hozzáférés";}i:50;a:4:{s:3:"key";s:11:"nav.address";s:2:"en";s:38:"Empadronamiento (Address Registration)";s:2:"es";s:15:"Empadronamiento";s:2:"hu";s:36:"Empadronamiento (Lakcímbejelentés)";}i:51;a:4:{s:3:"key";s:8:"nav.bank";s:2:"en";s:20:"Opening Bank Account";s:2:"es";s:27:"Apertura de Cuenta Bancaria";s:2:"hu";s:19:"Bankszámla nyitás";}i:52;a:4:{s:3:"key";s:21:"nav.digital-signature";s:2:"en";s:17:"Digital Signature";s:2:"es";s:13:"Firma Digital";s:2:"hu";s:21:"Digitális aláírás";}i:53;a:4:{s:3:"key";s:7:"nav.nie";s:2:"en";s:10:"NIE Number";s:2:"es";s:11:"Número NIE";s:2:"hu";s:9:"NIE szám";}i:54;a:4:{s:3:"key";s:10:"nav.notary";s:2:"en";s:17:"Power of Attorney";s:2:"es";s:14:"Poder Notarial";s:2:"hu";s:14:"Meghatalmazás";}i:55;a:4:{s:3:"key";s:13:"nav.residency";s:2:"en";s:27:"European Residence in Spain";s:2:"es";s:29:"Residencia Europea en España";s:2:"hu";s:33:"Európai tartózkodási engedély";}i:56;a:4:{s:3:"key";s:14:"nav.transcript";s:2:"en";s:16:"Utility Transfer";s:2:"es";s:36:"Cambio de Titularidad de Suministros";s:2:"hu";s:20:"Közüzemi átírás";}i:57;a:4:{s:3:"key";s:9:"nav_label";s:2:"en";s:16:"Quick Navigation";s:2:"es";s:19:"Navegación Rápida";s:2:"hu";s:17:"Gyors Navigáció";}i:58;a:4:{s:3:"key";s:9:"nie.badge";s:2:"en";s:8:"24–48h";s:2:"es";s:8:"24–48h";s:2:"hu";s:8:"24–48h";}i:59;a:4:{s:3:"key";s:10:"nie.h_uses";s:2:"en";s:20:"What is the NIE for?";s:2:"es";s:25:"¿Para qué sirve el NIE?";s:2:"hu";s:15:"Mire jó a NIE?";}i:60;a:4:{s:3:"key";s:9:"nie.intro";s:2:"en";s:294:"The <strong>Foreigner Identification Number (NIE)</strong> is a tax identification code assigned to foreign citizens who reside in Spain or need to carry out legal or administrative procedures there. It is the equivalent of the Tax Identification Number (NIF) for Spaniards, but for foreigners.";s:2:"es";s:348:"El <strong>Número de Identificación de Extranjero (NIE)</strong> es un código de identificación fiscal asignado a los ciudadanos extranjeros que residen en España o necesitan realizar trámites legales o administrativos en el país. Es el equivalente al Número de Identificación Fiscal (NIF) para los españoles, pero aplicado a extranjeros.";s:2:"hu";s:294:"A <strong>Külföldi Azonosítószám (NIE)</strong> egy adóazonosító kód, amelyet azoknak a külföldi állampolgároknak adnak ki, akik Spanyolországban élnek, vagy jogi, adminisztratív ügyeket intéznek ott. A spanyol adóazonosítónak (NIF) megfelelője, de külföldiek számára.";}i:61;a:4:{s:3:"key";s:8:"nie.note";s:2:"en";s:165:"The NIE is an essential document for any foreigner who wants to live, work, or carry out legal procedures in Spain. DOBERO can process your NIE within 24–48 hours.";s:2:"es";s:173:"El NIE es un documento esencial para cualquier extranjero que quiera vivir, trabajar o realizar trámites legales en España. DOBERO puede gestionar su NIE en 24–48 horas.";s:2:"hu";s:186:"A NIE elengedhetetlen dokumentum minden külföldinek, aki élni, dolgozni vagy jogi ügyeket intézni szeretne Spanyolországban. A DOBERO 24–48 órán belül intézi az Ön NIE-jét.";}i:62;a:4:{s:3:"key";s:9:"nie.title";s:2:"en";s:10:"NIE Number";s:2:"es";s:11:"Número NIE";s:2:"hu";s:9:"NIE szám";}i:63;a:4:{s:3:"key";s:10:"nie.uses.0";s:2:"en";s:74:"Buying or selling a property — essential for any real estate transaction";s:2:"es";s:90:"Comprar o vender una propiedad — imprescindible para cualquier transacción inmobiliaria";s:2:"hu";s:77:"Ingatlan vétele vagy eladása — elengedhetetlen minden ingatlanügyletnél";}i:64;a:4:{s:3:"key";s:10:"nie.uses.1";s:2:"en";s:51:"Opening a bank account — most banks require a NIE";s:2:"es";s:68:"Abrir una cuenta bancaria — la mayoría de los bancos lo requieren";s:2:"hu";s:53:"Bankszámla nyitása — a legtöbb bank megköveteli";}i:65;a:4:{s:3:"key";s:10:"nie.uses.2";s:2:"en";s:74:"Working in Spain — required for employment contracts and Social Security";s:2:"es";s:80:"Trabajar en España — necesario para contratos laborales y la Seguridad Social";s:2:"hu";s:104:"Munkavállalás Spanyolországban — szükséges munkaszerződésekhez és a Társadalombiztosításhoz";}i:66;a:4:{s:3:"key";s:10:"nie.uses.3";s:2:"en";s:57:"Driving in Spain — to obtain or renew a driving licence";s:2:"es";s:69:"Conducir en España — para obtener o renovar el permiso de conducir";s:2:"hu";s:88:"Autóvezetés Spanyolországban — jogosítvány igényléséhez vagy megújításához";}i:67;a:4:{s:3:"key";s:10:"nie.uses.4";s:2:"en";s:62:"Obtaining a health card — to access the public health system";s:2:"es";s:74:"Obtener la tarjeta sanitaria — para acceder al sistema público de salud";s:2:"hu";s:84:"Egészségügyi kártya igénylése — a közegészségügyi rendszer eléréséhez";}i:68;a:4:{s:3:"key";s:10:"nie.uses.5";s:2:"en";s:33:"Enrolling in university or school";s:2:"es";s:46:"Matricularse en la universidad o en el colegio";s:2:"hu";s:36:"Főiskolai vagy iskolai beiratkozás";}i:69;a:4:{s:3:"key";s:10:"nie.uses.6";s:2:"en";s:46:"Setting up a company or registering a business";s:2:"es";s:40:"Crear una empresa o registrar un negocio";s:2:"hu";s:45:"Cégalapítás vagy vállalkozás bejegyzése";}i:70;a:4:{s:3:"key";s:10:"nie.uses.7";s:2:"en";s:18:"Filing tax returns";s:2:"es";s:36:"Presentar declaraciones de impuestos";s:2:"hu";s:26:"Adóbevallás benyújtása";}i:71;a:4:{s:3:"key";s:10:"nie.uses.8";s:2:"en";s:36:"Obtaining a visa or residence permit";s:2:"es";s:41:"Obtener un visado o permiso de residencia";s:2:"hu";s:48:"Vízum vagy tartózkodási engedély igénylése";}i:72;a:4:{s:3:"key";s:16:"notary.actions.0";s:2:"en";s:40:"Signing contracts on behalf of the buyer";s:2:"es";s:40:"Firmar contratos en nombre del comprador";s:2:"hu";s:42:"Szerződések aláírása a vevő nevében";}i:73;a:4:{s:3:"key";s:16:"notary.actions.1";s:2:"en";s:52:"Managing the mortgage or any other type of financing";s:2:"es";s:60:"Gestionar la hipoteca o cualquier otro tipo de financiación";s:2:"hu";s:53:"Jelzáloghitel vagy egyéb finanszírozás intézése";}i:74;a:4:{s:3:"key";s:16:"notary.actions.2";s:2:"en";s:52:"Making the necessary payments on behalf of the buyer";s:2:"es";s:53:"Realizar los pagos necesarios en nombre del comprador";s:2:"hu";s:57:"A szükséges kifizetések teljesítése a vevő nevében";}i:75;a:4:{s:3:"key";s:16:"notary.actions.3";s:2:"en";s:49:"Managing the necessary documentation for the sale";s:2:"es";s:51:"Gestionar la documentación necesaria para la venta";s:2:"hu";s:54:"Az adásvételhez szükséges dokumentáció kezelése";}i:76;a:4:{s:3:"key";s:16:"notary.actions.4";s:2:"en";s:56:"Attending appointments with the seller, the notary, etc.";s:2:"es";s:49:"Asistir a citas con el vendedor, el notario, etc.";s:2:"hu";s:71:"Megjelenés az eladóval, közjegyzővel stb. folytatott találkozókon";}i:77;a:4:{s:3:"key";s:16:"notary.h_actions";s:2:"en";s:38:"Actions the representative can perform";s:2:"es";s:44:"Acciones que puede realizar el representante";s:2:"hu";s:48:"A képviselő által elvégezhető cselekmények";}i:78;a:4:{s:3:"key";s:13:"notary.h_uses";s:2:"en";s:39:"What is it used for when buying a home?";s:2:"es";s:47:"¿Para qué se utiliza al comprar una vivienda?";s:2:"hu";s:39:"Mire használják lakásvásárláskor?";}i:79;a:4:{s:3:"key";s:12:"notary.intro";s:2:"en";s:286:"A power of attorney between a home buyer and their representative gives the latter the legal authority to act on behalf of the buyer in all matters relating to the sale of the property. The buyer delegates their authority to the representative to perform certain actions in their place.";s:2:"es";s:305:"Un poder notarial entre un comprador de vivienda y su representante otorga a este último la autoridad legal para actuar en nombre del comprador en todos los asuntos relacionados con la venta del inmueble. El comprador delega su autoridad al representante para realizar determinadas acciones en su nombre.";s:2:"hu";s:297:"A lakásvásárló és képviselője közötti meghatalmazás jogi felhatalmazást ad a képviselőnek, hogy az ingatlan adásvételével kapcsolatos minden ügyben a vevő nevében járjon el. A vevő a képviselőre ruházza hatáskörét, hogy bizonyos intézkedéseket helyette elvégezhessen.";}i:80;a:4:{s:3:"key";s:11:"notary.note";s:2:"en";s:230:"The power of attorney must be granted before a notary and must clearly specify the representative''s powers. A poorly drafted power of attorney can lead to legal problems. Consult a lawyer to ensure it covers all the buyer''s needs.";s:2:"es";s:267:"El poder notarial debe ser otorgado ante notario y debe especificar claramente las facultades del representante. Un poder notarial mal redactado puede ocasionar problemas legales. Consulte a un abogado para asegurarse de que cubre todas las necesidades del comprador.";s:2:"hu";s:258:"A meghatalmazást közjegyző előtt kell megadni, és egyértelműen meg kell határoznia a képviselő jogkörét. A rosszul megfogalmazott meghatalmazás jogi problémákhoz vezethet. Forduljon ügyvédhez, hogy az megfeleljen a vevő összes igényének.";}i:81;a:4:{s:3:"key";s:12:"notary.title";s:2:"en";s:17:"Power of Attorney";s:2:"es";s:14:"Poder Notarial";s:2:"hu";s:14:"Meghatalmazás";}i:82;a:4:{s:3:"key";s:13:"notary.uses.0";s:2:"en";s:173:"<strong>If the buyer resides abroad:</strong> The power of attorney allows a representative in Spain to manage all procedures, without the buyer having to travel constantly.";s:2:"es";s:203:"<strong>Si el comprador reside en el extranjero:</strong> El poder notarial permite a un representante en España gestionar todos los trámites, sin que el comprador tenga que desplazarse constantemente.";s:2:"hu";s:206:"<strong>Ha a vevő külföldön él:</strong> A meghatalmazás lehetővé teszi, hogy egy spanyolországi képviselő intézze az összes ügymenetet, anélkül hogy a vevőnek folyamatosan utaznia kellene.";}i:83;a:4:{s:3:"key";s:13:"notary.uses.1";s:2:"en";s:167:"<strong>If the buyer cannot be present:</strong> Due to work, illness or other circumstances, the power of attorney allows their representative to act on their behalf.";s:2:"es";s:181:"<strong>Si el comprador no puede estar presente:</strong> Por motivos laborales, de salud u otras circunstancias, el poder notarial permite que su representante actúe en su nombre.";s:2:"hu";s:177:"<strong>Ha a vevő nem tud jelen lenni:</strong> Munkája, betegsége vagy egyéb körülmények miatt a meghatalmazás lehetővé teszi, hogy képviselője helyette járjon el.";}i:84;a:4:{s:3:"key";s:13:"notary.uses.2";s:2:"en";s:158:"<strong>To speed up the process:</strong> A representative with a power of attorney can make decisions and take action without the need for constant approval.";s:2:"es";s:150:"<strong>Para agilizar el proceso:</strong> Un representante con poder notarial puede tomar decisiones y actuar sin necesidad de aprobación constante.";s:2:"hu";s:171:"<strong>A folyamat felgyorsítása érdekében:</strong> A meghatalmazással rendelkező képviselő döntéseket hozhat és intézkedhet állandó jóváhagyás nélkül.";}i:85;a:4:{s:3:"key";s:13:"notary.uses.3";s:2:"en";s:171:"<strong>For added security:</strong> The buyer may prefer to have a lawyer or property manager handle the sale to ensure everything is done correctly according to the law.";s:2:"es";s:186:"<strong>Para mayor seguridad:</strong> El comprador puede preferir que un abogado o gestor inmobiliario gestione la venta para asegurarse de que todo se hace correctamente según la ley.";s:2:"hu";s:200:"<strong>A biztonság növelése érdekében:</strong> A vevő esetleg ügyvédet vagy ingatlankezelőt preferál az adásvétel lebonyolítására, hogy minden a törvénynek megfelelően történjen.";}i:86;a:4:{s:3:"key";s:16:"residency.docs.0";s:2:"en";s:29:"Valid passport or national ID";s:2:"es";s:24:"Pasaporte o DNI en vigor";s:2:"hu";s:47:"Érvényes útlevél vagy személyi igazolvány";}i:87;a:4:{s:3:"key";s:16:"residency.docs.1";s:2:"en";s:26:"Completed application form";s:2:"es";s:34:"Impreso de solicitud cumplimentado";s:2:"hu";s:32:"Kitöltött kérelemnyomtatvány";}i:88;a:4:{s:3:"key";s:16:"residency.docs.2";s:2:"en";s:49:"Proof of address in Spain (e.g., rental contract)";s:2:"es";s:67:"Justificante de domicilio en España (p. ej., contrato de alquiler)";s:2:"hu";s:59:"Spanyolországi lakcímigazolás (pl. bérleti szerződés)";}i:89;a:4:{s:3:"key";s:16:"residency.docs.3";s:2:"en";s:17:"Recent photograph";s:2:"es";s:20:"Fotografía reciente";s:2:"hu";s:15:"Friss fénykép";}i:90;a:4:{s:3:"key";s:16:"residency.docs.4";s:2:"en";s:27:"Payment of the relevant fee";s:2:"es";s:31:"Pago de la tasa correspondiente";s:2:"hu";s:30:"Az illetékes díj befizetése";}i:91;a:4:{s:3:"key";s:19:"residency.enables.0";s:2:"en";s:32:"Access to the Spanish job market";s:2:"es";s:34:"Acceso al mercado laboral español";s:2:"hu";s:40:"Hozzáférés a spanyol munkaerőpiachoz";}i:92;a:4:{s:3:"key";s:19:"residency.enables.1";s:2:"en";s:41:"Access to public healthcare and education";s:2:"es";s:42:"Acceso a la sanidad y educación públicas";s:2:"hu";s:59:"Hozzáférés az állami egészségügyhöz és oktatáshoz";}i:93;a:4:{s:3:"key";s:19:"residency.enables.2";s:2:"en";s:21:"Opening bank accounts";s:2:"es";s:29:"Apertura de cuentas bancarias";s:2:"hu";s:20:"Bankszámla nyitása";}i:94;a:4:{s:3:"key";s:19:"residency.enables.3";s:2:"en";s:39:"Applying for other permits and licences";s:2:"es";s:39:"Solicitud de otros permisos y licencias";s:2:"hu";s:43:"Egyéb engedélyek és licencek igénylése";}i:95;a:4:{s:3:"key";s:19:"residency.enables.4";s:2:"en";s:47:"Proving your address for administrative matters";s:2:"es";s:58:"Acreditación del domicilio para trámites administrativos";s:2:"hu";s:44:"Lakcím igazolása adminisztratív ügyekhez";}i:96;a:4:{s:3:"key";s:16:"residency.h_docs";s:2:"en";s:18:"Required documents";s:2:"es";s:21:"Documentos necesarios";s:2:"hu";s:24:"Szükséges dokumentumok";}i:97;a:4:{s:3:"key";s:19:"residency.h_enables";s:2:"en";s:34:"What the EU residence card enables";s:2:"es";s:45:"Qué permite la tarjeta de residencia europea";s:2:"hu";s:45:"Mire jogosít az EU-s tartózkodási kártya?";}i:98;a:4:{s:3:"key";s:21:"residency.h_mandatory";s:2:"en";s:16:"Is it mandatory?";s:2:"es";s:17:"¿Es obligatoria?";s:2:"hu";s:13:"Kötelező-e?";}i:99;a:4:{s:3:"key";s:15:"residency.intro";s:2:"en";s:215:"The <strong>European Residence certificate</strong> is issued to citizens of the EU, EEA, or Switzerland who live in Spain for more than three months. It is not a special visa, but official proof of legal residence.";s:2:"es";s:242:"El <strong>certificado de residencia europea</strong> se expide a los ciudadanos de la UE, el EEE o Suiza que residen en España durante más de tres meses. No es un visado especial, sino un documento oficial que acredita la residencia legal.";s:2:"hu";s:272:"Az <strong>európai tartózkodási igazolást</strong> azoknak az EU-, EGT- vagy svájci állampolgároknak adják ki, akik több mint három hónapig tartózkodnak Spanyolországban. Nem különleges vízum, hanem a jogszerű tartózkodást igazoló hivatalos dokumentum.";}i:100;a:4:{s:3:"key";s:19:"residency.mandatory";s:2:"en";s:200:"If you stay in Spain longer than three months, you must register as a resident. The physical card is not strictly mandatory, but it is the easiest and most practical way to prove your legal residence.";s:2:"es";s:205:"Si permanece en España más de tres meses, debe registrarse como residente. La tarjeta física no es estrictamente obligatoria, pero es la forma más sencilla y práctica de acreditar su residencia legal.";s:2:"hu";s:236:"Ha három hónapnál tovább tartózkodik Spanyolországban, tartózkodóként kell regisztrálnia. A fizikai kártya szigorúan nem kötelező, de ez a legegyszerűbb és legpraktikusabb módja a jogszerű tartózkodás igazolásának.";}i:101;a:4:{s:3:"key";s:14:"residency.note";s:2:"en";s:139:"You apply at the Immigration Office in your province of residence. Fees are usually low — check locally for updated costs and procedures.";s:2:"es";s:182:"La solicitud se presenta en la Oficina de Extranjería de su provincia de residencia. Las tasas suelen ser reducidas — consulte localmente los costes y procedimientos actualizados.";s:2:"hu";s:210:"A kérelmet a tartózkodási helye szerinti tartomány Bevándorlási Hivatalánál kell benyújtani. A díjak általában alacsonyak — érdeklődjön helyben az aktuális költségekről és eljárásokról.";}i:102;a:4:{s:3:"key";s:15:"residency.title";s:2:"en";s:27:"European Residence in Spain";s:2:"es";s:29:"Residencia Europea en España";s:2:"hu";s:33:"Európai tartózkodási engedély";}i:103;a:4:{s:3:"key";s:8:"subtitle";s:2:"en";s:6:"DOBERO";s:2:"es";s:6:"DOBERO";s:2:"hu";s:6:"DOBERO";}i:104;a:4:{s:3:"key";s:5:"title";s:2:"en";s:10:"Relocation";s:2:"es";s:12:"Reubicación";s:2:"hu";s:11:"Költözés";}i:105;a:4:{s:3:"key";s:17:"transcript.docs.0";s:2:"en";s:21:"Your ID or NIE number";s:2:"es";s:20:"DNI o número de NIE";s:2:"hu";s:36:"Személyi igazolvány vagy NIE szám";}i:106;a:4:{s:3:"key";s:17:"transcript.docs.1";s:2:"en";s:47:"Property details (address, cadastral reference)";s:2:"es";s:53:"Datos del inmueble (dirección, referencia catastral)";s:2:"hu";s:46:"Ingatlan adatai (cím, kataszteri hivatkozás)";}i:107;a:4:{s:3:"key";s:17:"transcript.docs.2";s:2:"en";s:43:"Bank account number (IBAN) for direct debit";s:2:"es";s:53:"Número de cuenta bancaria (IBAN) para domiciliación";s:2:"hu";s:48:"Bankszámlaszám (IBAN) a csoportos terheléshez";}i:108;a:4:{s:3:"key";s:17:"transcript.docs.3";s:2:"en";s:48:"A copy of the purchase deed (<em>escritura</em>)";s:2:"es";s:57:"Copia de la escritura de compraventa (<em>escritura</em>)";s:2:"hu";s:58:"Az adásvételi szerződés (<em>escritura</em>) másolata";}i:109;a:4:{s:3:"key";s:17:"transcript.h_docs";s:2:"en";s:24:"What you need to provide";s:2:"es";s:21:"Qué necesita aportar";s:2:"hu";s:21:"Mit kell benyújtani?";}i:110;a:4:{s:3:"key";s:16:"transcript.h_why";s:2:"en";s:14:"Why it matters";s:2:"es";s:22:"Por qué es importante";s:2:"hu";s:14:"Miért fontos?";}i:111;a:4:{s:3:"key";s:16:"transcript.intro";s:2:"en";s:200:"A <strong>utility transfer</strong> (sometimes called utility transcription) refers to changing utility contracts — electricity, water, and gas — into the new owner''s name after buying a property.";s:2:"es";s:173:"El <strong>cambio de titularidad de suministros</strong> consiste en traspasar los contratos de luz, agua y gas a nombre del nuevo propietario tras la compra de un inmueble.";s:2:"hu";s:157:"A <strong>közüzemi átírás</strong> az ingatlan megvásárlása után az áram-, víz- és gázszerződések új tulajdonosra való átírását jelenti.";}i:112;a:4:{s:3:"key";s:15:"transcript.note";s:2:"en";s:162:"This is a simple but important step immediately after completing the property purchase. DOBERO handles utility transfers as part of our post-sale support service.";s:2:"es";s:199:"Este es un paso sencillo pero importante inmediatamente después de completar la compra del inmueble. DOBERO gestiona el cambio de titularidad como parte de nuestro servicio de asistencia post-venta.";s:2:"hu";s:197:"Ez egyszerű, de fontos lépés közvetlenül az ingatlanvásárlás befejezése után. A DOBERO az értékesítés utáni támogatási szolgáltatásunk keretében intézi a közüzemi átírást.";}i:113;a:4:{s:3:"key";s:16:"transcript.title";s:2:"en";s:16:"Utility Transfer";s:2:"es";s:36:"Cambio de Titularidad de Suministros";s:2:"hu";s:20:"Közüzemi átírás";}i:114;a:4:{s:3:"key";s:16:"transcript.why.0";s:2:"en";s:40:"Bills are issued in the new owner''s name";s:2:"es";s:53:"Las facturas se emiten a nombre del nuevo propietario";s:2:"hu";s:46:"A számlák az új tulajdonos nevére szólnak";}i:115;a:4:{s:3:"key";s:16:"transcript.why.1";s:2:"en";s:57:"Legal responsibility for payments is properly transferred";s:2:"es";s:69:"La responsabilidad legal de los pagos queda correctamente transferida";s:2:"hu";s:72:"A fizetési jogi felelősség megfelelően átszáll az új tulajdonosra";}i:116;a:4:{s:3:"key";s:16:"transcript.why.2";s:2:"en";s:57:"Services continue without interruption after the purchase";s:2:"es";s:57:"Los servicios continúan sin interrupción tras la compra";s:2:"hu";s:75:"A szolgáltatások a vásárlás után megszakítás nélkül folytatódnak";}}', '2095103530');
INSERT INTO "cache" ("key", "value", "expiration") VALUES ('dobero-home-creator-cache-translations.contact', 'a:14:{i:0;a:4:{s:3:"key";s:7:"CONTACT";s:2:"en";s:7:"CONTACT";s:2:"es";s:8:"CONTACTO";s:2:"hu";s:9:"KAPCSOLAT";}i:1;a:4:{s:3:"key";s:7:"Contact";s:2:"en";s:7:"Contact";s:2:"es";s:8:"Contacto";s:2:"hu";s:9:"Kapcsolat";}i:2;a:4:{s:3:"key";s:19:"Contact Information";s:2:"en";s:19:"Contact Information";s:2:"es";s:24:"Información de contacto";s:2:"hu";s:17:"Kapcsolati adatok";}i:3;a:4:{s:3:"key";s:10:"First Name";s:2:"en";s:10:"First Name";s:2:"es";s:6:"Nombre";s:2:"hu";s:11:"Keresztnév";}i:4;a:4:{s:3:"key";s:9:"Last Name";s:2:"en";s:9:"Last Name";s:2:"es";s:8:"Apellido";s:2:"hu";s:12:"Vezetéknév";}i:5;a:4:{s:3:"key";s:5:"Email";s:2:"en";s:5:"Email";s:2:"es";s:19:"Correo electrónico";s:2:"hu";s:11:"E-mail cím";}i:6;a:4:{s:3:"key";s:5:"Phone";s:2:"en";s:5:"Phone";s:2:"es";s:9:"Teléfono";s:2:"hu";s:12:"Telefonszám";}i:7;a:4:{s:3:"key";s:12:"Inquiry Type";s:2:"en";s:12:"Inquiry Type";s:2:"es";s:16:"Tipo de consulta";s:2:"hu";s:19:"Megkeresés típusa";}i:8;a:4:{s:3:"key";s:15:"General Inquiry";s:2:"en";s:15:"General Inquiry";s:2:"es";s:16:"Consulta general";s:2:"hu";s:25:"Általános érdeklődés";}i:9;a:4:{s:3:"key";s:6:"Buying";s:2:"en";s:6:"Buying";s:2:"es";s:6:"Compra";s:2:"hu";s:11:"Vásárlás";}i:10;a:4:{s:3:"key";s:7:"Renting";s:2:"en";s:7:"Renting";s:2:"es";s:8:"Alquiler";s:2:"hu";s:8:"Bérlés";}i:11;a:4:{s:3:"key";s:7:"Message";s:2:"en";s:7:"Message";s:2:"es";s:7:"Mensaje";s:2:"hu";s:7:"Üzenet";}i:12;a:4:{s:3:"key";s:31:"Let''s Talk About Your Next Move";s:2:"en";s:31:"Let''s Talk About Your Next Move";s:2:"es";s:28:"Hablemos de su próximo paso";s:2:"hu";s:38:"Beszéljük meg a következő lépést";}i:13;a:4:{s:3:"key";s:123:"Share your goals and DOBERO HOME CREATOR will help you shortlist properties, assess opportunities, and plan the next steps.";s:2:"en";s:123:"Share your goals and DOBERO HOME CREATOR will help you shortlist properties, assess opportunities, and plan the next steps.";s:2:"es";s:139:"Comparta sus objetivos y DOBERO HOME CREATOR le ayudará a seleccionar propiedades, evaluar oportunidades y planificar los próximos pasos.";s:2:"hu";s:156:"Ossza meg céljait, és a DOBERO HOME CREATOR segít kiválasztani az ingatlanokat, értékelni a lehetőségeket és megtervezni a következő lépéseket.";}}', '2095103539');
INSERT INTO "cache" ("key", "value", "expiration") VALUES ('dobero-home-creator-cache-translations.specials', 'a:46:{i:0;a:4:{s:3:"key";s:16:"Special Services";s:2:"en";s:16:"Special Services";s:2:"es";s:20:"Servicios especiales";s:2:"hu";s:29:"Különleges szolgáltatások";}i:1;a:4:{s:3:"key";s:112:"Expert property inspection, hidden defect investigation, waterproofing and forensic support on the Costa Blanca.";s:2:"en";s:112:"Expert property inspection, hidden defect investigation, waterproofing and forensic support on the Costa Blanca.";s:2:"es";s:129:"Inspección técnica de propiedades, investigación de defectos ocultos, impermeabilización y apoyo pericial en la Costa Blanca.";s:2:"hu";s:129:"Szakszerű ingatlanvizsgálat, rejtett hibák feltárása, szigetelési megoldások és szakértői támogatás a Costa Blancán.";}i:2;a:4:{s:3:"key";s:30:"Technical Condition Assessment";s:2:"en";s:30:"Technical Condition Assessment";s:2:"es";s:31:"Evaluación del estado técnico";s:2:"hu";s:27:"Műszaki állapotfelmérés";}i:3;a:4:{s:3:"key";s:27:"Discovery of Hidden Defects";s:2:"en";s:27:"Discovery of Hidden Defects";s:2:"es";s:30:"Detección de defectos ocultos";s:2:"hu";s:26:"Rejtett hibák feltárása";}i:4;a:4:{s:3:"key";s:23:"Waterproofing Solutions";s:2:"en";s:23:"Waterproofing Solutions";s:2:"es";s:33:"Soluciones de impermeabilización";s:2:"hu";s:24:"Szigetelési megoldások";}i:5;a:4:{s:3:"key";s:23:"Forensic Expert Support";s:2:"en";s:23:"Forensic Expert Support";s:2:"es";s:24:"Apoyo de perito judicial";s:2:"hu";s:35:"Bírósági szakértői támogatás";}i:6;a:4:{s:3:"key";s:41:"Technical Property Survey Before Purchase";s:2:"en";s:41:"Technical Property Survey Before Purchase";s:2:"es";s:55:"Inspección técnica de la propiedad antes de la compra";s:2:"hu";s:48:"Ingatlan műszaki felmérése vásárlás előtt";}i:7;a:4:{s:3:"key";s:252:"Before purchasing a property, I provide a comprehensive technical survey, which I personally coordinate with trusted professionals. We thoroughly examine the structural condition, mechanical systems, moisture issues, and any potential renovation risks.";s:2:"en";s:252:"Before purchasing a property, I provide a comprehensive technical survey, which I personally coordinate with trusted professionals. We thoroughly examine the structural condition, mechanical systems, moisture issues, and any potential renovation risks.";s:2:"es";s:269:"Antes de comprar una propiedad, realizo una inspección técnica exhaustiva, que coordino personalmente con profesionales de confianza. Examinamos detalladamente el estado estructural, los sistemas mecánicos, los problemas de humedad y los posibles riesgos de reforma.";s:2:"hu";s:298:"Ingatlan vásárlása előtt átfogó műszaki felmérést végzek, amelyet személyesen koordinálok megbízható szakemberekkel. Alaposan megvizsgáljuk az épület szerkezeti állapotát, a gépészeti rendszereket, a nedvességproblémákat és a felújítással járó esetleges kockázatokat.";}i:8;a:4:{s:3:"key";s:255:"My aim is to ensure that my client has a clear understanding of possible future costs and hidden risks. A detailed and easy-to-understand report is provided following the inspection. This allows you to make a safe and well-informed decision before buying.";s:2:"en";s:255:"My aim is to ensure that my client has a clear understanding of possible future costs and hidden risks. A detailed and easy-to-understand report is provided following the inspection. This allows you to make a safe and well-informed decision before buying.";s:2:"es";s:261:"Mi objetivo es que el cliente tenga una comprensión clara de los posibles costes futuros y los riesgos ocultos. Tras la inspección se facilita un informe detallado y comprensible, que le permite tomar una decisión segura y bien fundamentada antes de comprar.";s:2:"hu";s:290:"Célom, hogy ügyfeleim egyértelmű képet kapjanak a lehetséges jövőbeli költségekről és rejtett kockázatokról. A felmérés után részletes, könnyen érthető jelentést készítünk. Ez lehetővé teszi, hogy biztonságos és megalapozott döntést hozzon vásárlás előtt.";}i:9;a:4:{s:3:"key";s:15:"What we examine";s:2:"en";s:15:"What we examine";s:2:"es";s:15:"Qué examinamos";s:2:"hu";s:15:"Mit vizsgálunk";}i:10;a:4:{s:3:"key";s:55:"Structural condition of walls, ceilings and foundations";s:2:"en";s:55:"Structural condition of walls, ceilings and foundations";s:2:"es";s:49:"Estado estructural de paredes, techos y cimientos";s:2:"hu";s:53:"Falak, mennyezetek és alapozás szerkezeti állapota";}i:11;a:4:{s:3:"key";s:41:"Plumbing, drainage and electrical systems";s:2:"en";s:41:"Plumbing, drainage and electrical systems";s:2:"es";s:56:"Instalaciones de fontanería, saneamiento y electricidad";s:2:"hu";s:42:"Víz-, csatorna- és elektromos rendszerek";}i:12;a:4:{s:3:"key";s:42:"Moisture levels and signs of water ingress";s:2:"en";s:42:"Moisture levels and signs of water ingress";s:2:"es";s:53:"Niveles de humedad e indicios de filtraciones de agua";s:2:"hu";s:41:"Nedvességszint és vízbeáramlás jelei";}i:13;a:4:{s:3:"key";s:40:"Roof and terrace waterproofing integrity";s:2:"en";s:40:"Roof and terrace waterproofing integrity";s:2:"es";s:58:"Integridad de la impermeabilización de cubierta y terraza";s:2:"hu";s:43:"Tető és terasz szigetelésének állapota";}i:14;a:4:{s:3:"key";s:54:"Quality and condition of windows, doors and insulation";s:2:"en";s:54:"Quality and condition of windows, doors and insulation";s:2:"es";s:51:"Calidad y estado de ventanas, puertas y aislamiento";s:2:"hu";s:59:"Ablakok, ajtók és hőszigetelés minősége és állapota";}i:15;a:4:{s:3:"key";s:41:"Estimated renovation costs and risk areas";s:2:"en";s:41:"Estimated renovation costs and risk areas";s:2:"es";s:45:"Costes estimados de reforma y zonas de riesgo";s:2:"hu";s:60:"Becsült felújítási költségek és kockázati területek";}i:16;a:4:{s:3:"key";s:137:"The inspection report is provided in writing in your language, with photos and cost estimates — giving you full clarity before signing.";s:2:"en";s:137:"The inspection report is provided in writing in your language, with photos and cost estimates — giving you full clarity before signing.";s:2:"es";s:152:"El informe de inspección se entrega por escrito en su idioma, con fotografías y estimaciones de costes, para que tenga plena claridad antes de firmar.";s:2:"hu";s:170:"A vizsgálati jelentés írásban, az Ön nyelvén kerül átadásra, fényképekkel és költségbecsléssel — teljes átláthatóságot biztosítva aláírás előtt.";}i:17;a:4:{s:3:"key";s:32:"Identification of Hidden Defects";s:2:"en";s:32:"Identification of Hidden Defects";s:2:"es";s:35:"Identificación de defectos ocultos";s:2:"hu";s:28:"Rejtett hibák azonosítása";}i:18;a:4:{s:3:"key";s:254:"Beyond visible issues, I place strong emphasis on identifying hidden defects. Drawing on my experience and working with specialist partners, we investigate structural cracks, damp problems, insulation deficiencies, and previously poorly executed repairs.";s:2:"en";s:254:"Beyond visible issues, I place strong emphasis on identifying hidden defects. Drawing on my experience and working with specialist partners, we investigate structural cracks, damp problems, insulation deficiencies, and previously poorly executed repairs.";s:2:"es";s:291:"Más allá de los problemas visibles, pongo especial énfasis en identificar los defectos ocultos. Apoyándome en mi experiencia y en colaboradores especializados, investigamos grietas estructurales, problemas de humedad, deficiencias de aislamiento y reparaciones anteriores mal ejecutadas.";s:2:"hu";s:292:"A látható problémákon túl nagy hangsúlyt fektetek a rejtett hibák azonosítására. Tapasztalatomra és szakember partnerekre támaszkodva megvizsgáljuk a szerkezeti repedéseket, nedvességproblémákat, szigetelési hiányosságokat és a korábban rosszul elvégzett javításokat.";}i:19;a:4:{s:3:"key";s:229:"These issues are often not visible at first glance but can lead to significant expenses later. My goal is to prevent unpleasant surprises after completion. All findings are properly documented and clearly explained to the client.";s:2:"en";s:229:"These issues are often not visible at first glance but can lead to significant expenses later. My goal is to prevent unpleasant surprises after completion. All findings are properly documented and clearly explained to the client.";s:2:"es";s:265:"Estos problemas no siempre son visibles a primera vista, pero pueden generar gastos considerables más adelante. Mi objetivo es evitar sorpresas desagradables tras la compra. Todos los hallazgos quedan debidamente documentados y se explican con claridad al cliente.";s:2:"hu";s:294:"Ezek a problémák gyakran nem láthatók első ránézésre, de később jelentős kiadásokat okozhatnak. Célom az, hogy megakadályozzam a kellemetlen meglepetéseket az adásvétel után. Minden megállapítást megfelelően dokumentálunk és egyértelműen elmagyarázunk az ügyfélnek.";}i:20;a:4:{s:3:"key";s:32:"Common hidden defects we uncover";s:2:"en";s:32:"Common hidden defects we uncover";s:2:"es";s:42:"Defectos ocultos habituales que detectamos";s:2:"hu";s:44:"Gyakori rejtett hibák, amelyeket feltárunk";}i:21;a:4:{s:3:"key";s:51:"Structural cracks concealed behind plaster or paint";s:2:"en";s:51:"Structural cracks concealed behind plaster or paint";s:2:"es";s:55:"Grietas estructurales ocultas bajo el yeso o la pintura";s:2:"hu";s:57:"Vakolat vagy festék mögé rejtett szerkezeti repedések";}i:22;a:4:{s:3:"key";s:52:"Water ingress from roofs, terraces or external walls";s:2:"en";s:52:"Water ingress from roofs, terraces or external walls";s:2:"es";s:66:"Filtraciones de agua procedentes de cubiertas, terrazas o fachadas";s:2:"hu";s:63:"Tetőkről, teraszokról vagy külső falakról beáramló víz";}i:23;a:4:{s:3:"key";s:53:"Substandard or non-compliant electrical installations";s:2:"en";s:53:"Substandard or non-compliant electrical installations";s:2:"es";s:64:"Instalaciones eléctricas deficientes o no conformes a normativa";s:2:"hu";s:70:"Nem megfelelő vagy szabványnak nem megfelelő elektromos szerelések";}i:24;a:4:{s:3:"key";s:39:"Poorly insulated or unventilated spaces";s:2:"en";s:39:"Poorly insulated or unventilated spaces";s:2:"es";s:49:"Espacios mal aislados o sin ventilación adecuada";s:2:"hu";s:42:"Rosszul szigetelt vagy szellőzetlen terek";}i:25;a:4:{s:3:"key";s:51:"Previous repairs carried out without proper permits";s:2:"en";s:51:"Previous repairs carried out without proper permits";s:2:"es";s:68:"Reparaciones anteriores realizadas sin los permisos correspondientes";s:2:"hu";s:51:"Korábban engedély nélkül elvégzett javítások";}i:26;a:4:{s:3:"key";s:127:"Many defects are intentionally hidden by sellers. An independent survey protects your investment and your negotiating position.";s:2:"en";s:127:"Many defects are intentionally hidden by sellers. An independent survey protects your investment and your negotiating position.";s:2:"es";s:147:"Muchos defectos son ocultados intencionadamente por los vendedores. Una inspección independiente protege su inversión y su posición negociadora.";s:2:"hu";s:127:"Sok hibát szándékosan rejtenek el az eladók. Egy független felmérés védi befektetését és tárgyalási pozícióját.";}i:27;a:4:{s:3:"key";s:210:"Due to the climate in the Costa Blanca region, damp and water ingress can be common problems. Together with my own team, I provide professional waterproofing solutions for roofs, terraces, basements, and walls.";s:2:"en";s:210:"Due to the climate in the Costa Blanca region, damp and water ingress can be common problems. Together with my own team, I provide professional waterproofing solutions for roofs, terraces, basements, and walls.";s:2:"es";s:227:"Debido al clima de la Costa Blanca, la humedad y las filtraciones de agua pueden ser problemas frecuentes. Junto con mi equipo, ofrezco soluciones profesionales de impermeabilización para cubiertas, terrazas, sótanos y muros.";s:2:"hu";s:213:"A Costa Blanca éghajlata miatt a nedvesség és a vízbeáramlás gyakori probléma lehet. Saját csapatommal professzionális szigetelési megoldásokat nyújtok tetőkhöz, teraszokhoz, pincékhez és falakhoz.";}i:28;a:4:{s:3:"key";s:228:"We use modern materials and proven technologies to ensure long-term protection. I personally supervise each project to guarantee high standards of workmanship. Our objective is to preserve and enhance the value of your property.";s:2:"en";s:228:"We use modern materials and proven technologies to ensure long-term protection. I personally supervise each project to guarantee high standards of workmanship. Our objective is to preserve and enhance the value of your property.";s:2:"es";s:252:"Utilizamos materiales modernos y tecnologías contrastadas para garantizar una protección duradera. Superviso personalmente cada proyecto para asegurar altos estándares de ejecución. Nuestro objetivo es preservar y aumentar el valor de su propiedad.";s:2:"hu";s:256:"Modern anyagokat és bevált technológiákat alkalmazunk a hosszú távú védelem érdekében. Személyesen felügyelem minden projektet a magas minőségi standardok garantálása érdekében. Célunk az ingatlan értékének megőrzése és növelése.";}i:29;a:4:{s:3:"key";s:19:"Areas we waterproof";s:2:"en";s:19:"Areas we waterproof";s:2:"es";s:27:"Zonas que impermeabilizamos";s:2:"hu";s:34:"Területek, amelyeket szigetelünk";}i:30;a:4:{s:3:"key";s:37:"Flat roofs and pitched roof membranes";s:2:"en";s:37:"Flat roofs and pitched roof membranes";s:2:"es";s:50:"Cubiertas planas y membranas de cubierta inclinada";s:2:"hu";s:38:"Lapostetők és nyeregtető-membránok";}i:31;a:4:{s:3:"key";s:40:"Terraces, balconies and outdoor surfaces";s:2:"en";s:40:"Terraces, balconies and outdoor surfaces";s:2:"es";s:43:"Terrazas, balcones y superficies exteriores";s:2:"hu";s:44:"Teraszok, erkélyek és kültéri felületek";}i:32;a:4:{s:3:"key";s:31:"Basements and below-grade walls";s:2:"en";s:31:"Basements and below-grade walls";s:2:"es";s:29:"Sótanos y muros bajo rasante";s:2:"hu";s:35:"Pincék és terepszint alatti falak";}i:33;a:4:{s:3:"key";s:36:"Wet rooms — bathrooms and kitchens";s:2:"en";s:36:"Wet rooms — bathrooms and kitchens";s:2:"es";s:32:"Zonas húmedas: baños y cocinas";s:2:"hu";s:50:"Nedves helyiségek — fürdőszobák és konyhák";}i:34;a:4:{s:3:"key";s:24:"External facade coatings";s:2:"en";s:24:"External facade coatings";s:2:"es";s:34:"Revestimientos de fachada exterior";s:2:"hu";s:28:"Külső homlokzati bevonatok";}i:35;a:4:{s:3:"key";s:101:"All waterproofing work comes with a guarantee and uses materials rated for the Mediterranean climate.";s:2:"en";s:101:"All waterproofing work comes with a guarantee and uses materials rated for the Mediterranean climate.";s:2:"es";s:123:"Todos los trabajos de impermeabilización incluyen garantía y utilizan materiales homologados para el clima mediterráneo.";s:2:"hu";s:108:"Minden szigetelési munka garanciával jár, és mediterrán éghajlatra minősített anyagokat használunk.";}i:36;a:4:{s:3:"key";s:20:"Court Expert Support";s:2:"en";s:20:"Court Expert Support";s:2:"es";s:24:"Apoyo de perito judicial";s:2:"hu";s:35:"Bírósági szakértői támogatás";}i:37;a:4:{s:3:"key";s:225:"If a seller has concealed relevant defects or information during the sale, we provide court expert support. Together with my certified expert colleague, we prepare an official technical report regarding the identified issues.";s:2:"en";s:225:"If a seller has concealed relevant defects or information during the sale, we provide court expert support. Together with my certified expert colleague, we prepare an official technical report regarding the identified issues.";s:2:"es";s:224:"Si un vendedor ha ocultado defectos o información relevante durante la venta, ofrecemos apoyo pericial judicial. Junto con mi colega perito certificado, elaboramos un informe técnico oficial sobre los problemas detectados.";s:2:"hu";s:256:"Ha az eladó az adásvétel során lényeges hibákat vagy információkat titkolt el, bírósági szakértői támogatást nyújtunk. Tanúsított szakértő kollégámmal együtt hivatalos műszaki jelentést készítünk az azonosított problémákról.";}i:38;a:4:{s:3:"key";s:251:"All necessary technical evidence is professionally documented and suitable for use in legal proceedings. We firmly represent our clients'' interests in dispute situations. Our aim is to ensure that buyers receive full professional and legal protection.";s:2:"en";s:251:"All necessary technical evidence is professionally documented and suitable for use in legal proceedings. We firmly represent our clients'' interests in dispute situations. Our aim is to ensure that buyers receive full professional and legal protection.";s:2:"es";s:291:"Toda la evidencia técnica necesaria queda documentada profesionalmente y es apta para procedimientos legales. Defendemos con firmeza los intereses de nuestros clientes en situaciones de conflicto. Nuestro objetivo es que los compradores reciban protección profesional y jurídica completa.";s:2:"hu";s:273:"Minden szükséges műszaki bizonyítékot professzionálisan dokumentálunk, és az alkalmas jogi eljárásban való felhasználásra. Határozottan képviseljük ügyfeleink érdekeit vitás helyzetekben. Célunk, hogy a vevők teljes szakmai és jogi védelmet kapjanak.";}i:39;a:4:{s:3:"key";s:29:"What the expert report covers";s:2:"en";s:29:"What the expert report covers";s:2:"es";s:30:"Contenido del informe pericial";s:2:"hu";s:37:"Mit tartalmaz a szakértői jelentés";}i:40;a:4:{s:3:"key";s:63:"Official written assessment of structural and technical defects";s:2:"en";s:63:"Official written assessment of structural and technical defects";s:2:"es";s:69:"Evaluación escrita oficial de los defectos estructurales y técnicos";s:2:"hu";s:65:"Szerkezeti és műszaki hibák hivatalos írásbeli értékelése";}i:41;a:4:{s:3:"key";s:45:"Photo and video documentation of all findings";s:2:"en";s:45:"Photo and video documentation of all findings";s:2:"es";s:62:"Documentación fotográfica y en vídeo de todos los hallazgos";s:2:"hu";s:57:"Összes megállapítás fotó- és videódokumentációja";}i:42;a:4:{s:3:"key";s:49:"Estimated cost of damage and required remediation";s:2:"en";s:49:"Estimated cost of damage and required remediation";s:2:"es";s:58:"Coste estimado de los daños y las reparaciones necesarias";s:2:"hu";s:58:"A károk és a szükséges javítások becsült költsége";}i:43;a:4:{s:3:"key";s:60:"Statement on whether defects were pre-existing and concealed";s:2:"en";s:60:"Statement on whether defects were pre-existing and concealed";s:2:"es";s:68:"Dictamen sobre si los defectos eran preexistentes y fueron ocultados";s:2:"hu";s:80:"Nyilatkozat arról, hogy a hibák előzetesen fennálltak és el lettek-e rejtve";}i:44;a:4:{s:3:"key";s:56:"Document package suitable for court or legal proceedings";s:2:"en";s:56:"Document package suitable for court or legal proceedings";s:2:"es";s:64:"Paquete documental apto para procedimientos judiciales o legales";s:2:"hu";s:60:"Bírósági vagy jogi eljáráshoz alkalmas dokumentumcsomag";}i:45;a:4:{s:3:"key";s:124:"Our forensic expert reports are admissible in Spanish courts and can support claims for compensation or contract rescission.";s:2:"en";s:124:"Our forensic expert reports are admissible in Spanish courts and can support claims for compensation or contract rescission.";s:2:"es";s:151:"Nuestros informes periciales son admisibles en los tribunales españoles y pueden respaldar reclamaciones de indemnización o resolución de contratos.";s:2:"hu";s:137:"Szakértői jelentéseink elfogadhatók a spanyol bíróságokon, és kártérítési igényeket vagy szerződésbontást támogathatnak.";}}', '2095103732');
INSERT INTO "cache" ("key", "value", "expiration") VALUES ('dobero-home-creator-cache-translations.construction', 'a:34:{i:0;a:4:{s:3:"key";s:99:"Full and partial renovations, turnkey construction. Quality is not an option — it is a principle.";s:2:"en";s:99:"Full and partial renovations, turnkey construction. Quality is not an option — it is a principle.";s:2:"es";s:105:"Reformas totales y parciales, construcción llave en mano. La calidad no es una opción, es un principio.";s:2:"hu";s:103:"Teljes és részleges felújítások, kulcsrakész kivitelezés. A minőség nem opció — ez alapelv.";}i:1;a:4:{s:3:"key";s:20:"General Construction";s:2:"en";s:20:"General Construction";s:2:"es";s:21:"Construcción general";s:2:"hu";s:24:"Általános kivitelezés";}i:2;a:4:{s:3:"key";s:13:"Refurbishment";s:2:"en";s:13:"Refurbishment";s:2:"es";s:15:"Reforma parcial";s:2:"hu";s:23:"Részleges felújítás";}i:3;a:4:{s:3:"key";s:18:"Permit Acquisition";s:2:"en";s:18:"Permit Acquisition";s:2:"es";s:22:"Obtención de permisos";s:2:"hu";s:24:"Engedélyek megszerzése";}i:4;a:4:{s:3:"key";s:10:"References";s:2:"en";s:10:"References";s:2:"es";s:11:"Referencias";s:2:"hu";s:12:"Referenciák";}i:5;a:4:{s:3:"key";s:129:"When our clients commission full general construction from us, we take over the entire process from planning to turnkey handover.";s:2:"en";s:129:"When our clients commission full general construction from us, we take over the entire process from planning to turnkey handover.";s:2:"es";s:155:"Cuando nuestros clientes nos encargan una construcción general completa, asumimos todo el proceso, desde la planificación hasta la entrega llave en mano.";s:2:"hu";s:149:"Amikor ügyfeleink teljes körű általános kivitelezést bíznak ránk, átvesszük az egész folyamatot a tervezéstől a kulcsrakész átadásig.";}i:6;a:4:{s:3:"key";s:34:"1. Condition Assessment & Planning";s:2:"en";s:34:"1. Condition Assessment & Planning";s:2:"es";s:42:"1. Evaluación del estado y planificación";s:2:"hu";s:35:"1. Állapotfelmérés és tervezés";}i:7;a:4:{s:3:"key";s:191:"We start with a detailed technical survey, then align with the client''s needs, style and budget. Where needed we prepare interior design and technical plans, and optimise the property layout.";s:2:"en";s:191:"We start with a detailed technical survey, then align with the client''s needs, style and budget. Where needed we prepare interior design and technical plans, and optimise the property layout.";s:2:"es";s:252:"Comenzamos con una inspección técnica detallada y alineamos el trabajo con las necesidades, el estilo y el presupuesto del cliente. Si es necesario, elaboramos proyectos de interiorismo y planos técnicos, y optimizamos la distribución del inmueble.";s:2:"hu";s:244:"Részletes műszaki felméréssel kezdünk, majd igazodunk az ügyfél igényeihez, stílusához és költségvetéséhez. Szükség esetén belsőépítészeti és műszaki terveket készítünk, és optimalizáljuk az ingatlan elrendezését.";}i:8;a:4:{s:3:"key";s:27:"2. Permits & Administration";s:2:"en";s:27:"2. Permits & Administration";s:2:"es";s:37:"2. Permisos y gestión administrativa";s:2:"hu";s:32:"2. Engedélyek és ügyintézés";}i:9;a:4:{s:3:"key";s:147:"We handle all required municipal permits, notifications and official procedures. We liaise with local authorities and utility providers throughout.";s:2:"en";s:147:"We handle all required municipal permits, notifications and official procedures. We liaise with local authorities and utility providers throughout.";s:2:"es";s:199:"Gestionamos todos los permisos municipales necesarios, notificaciones y trámites oficiales. Mantenemos contacto con las autoridades locales y las compañías suministradoras durante todo el proceso.";s:2:"hu";s:187:"Intézünk minden szükséges hatósági engedélyt, bejelentést és hivatalos eljárást. Az egész folyamat során kapcsolatot tartunk a helyi hatóságokkal és közszolgáltatókkal.";}i:10;a:4:{s:3:"key";s:32:"3. Demolition & Structural Works";s:2:"en";s:32:"3. Demolition & Structural Works";s:2:"es";s:39:"3. Demolición y trabajos estructurales";s:2:"hu";s:34:"3. Bontási és szerkezeti munkák";}i:11;a:4:{s:3:"key";s:166:"We carry out demolition, wall relocation, floor-plan alterations and, where required, structural reinforcements — all based on structural and technical assessments.";s:2:"en";s:166:"We carry out demolition, wall relocation, floor-plan alterations and, where required, structural reinforcements — all based on structural and technical assessments.";s:2:"es";s:187:"Realizamos demoliciones, traslado de tabiques, modificaciones de distribución y, cuando es necesario, refuerzos estructurales, todo ello basado en evaluaciones estructurales y técnicas.";s:2:"hu";s:183:"Elvégezzük a bontást, falak áthelyezését, alaprajzi módosításokat és szükség esetén szerkezeti megerősítéseket — mindezt statikai és műszaki felmérések alapján.";}i:12;a:4:{s:3:"key";s:34:"4. Mechanical & Electrical Systems";s:2:"en";s:34:"4. Mechanical & Electrical Systems";s:2:"es";s:41:"4. Instalaciones mecánicas y eléctricas";s:2:"hu";s:38:"4. Gépészeti és villamos rendszerek";}i:13;a:4:{s:3:"key";s:159:"Full water, drainage and electrical network renovation or replacement. We install air conditioning, underfloor heating, heat pumps or energy-efficient systems.";s:2:"en";s:159:"Full water, drainage and electrical network renovation or replacement. We install air conditioning, underfloor heating, heat pumps or energy-efficient systems.";s:2:"es";s:191:"Renovación o sustitución completa de las redes de agua, saneamiento y electricidad. Instalamos aire acondicionado, suelo radiante, bombas de calor o sistemas de alta eficiencia energética.";s:2:"hu";s:178:"Teljes víz-, csatorna- és elektromos hálózat felújítása vagy cseréje. Légkondicionálót, padlófűtést, hőszivattyút vagy energiahatékony rendszereket telepítünk.";}i:14;a:4:{s:3:"key";s:35:"5. Insulation & Energy Improvements";s:2:"en";s:35:"5. Insulation & Energy Improvements";s:2:"es";s:37:"5. Aislamiento y mejoras energéticas";s:2:"hu";s:44:"5. Szigetelés és energetikai fejlesztések";}i:15;a:4:{s:3:"key";s:124:"Waterproofing, thermal insulation, roof and terrace insulation. Our goal is low running costs and long-term value retention.";s:2:"en";s:124:"Waterproofing, thermal insulation, roof and terrace insulation. Our goal is low running costs and long-term value retention.";s:2:"es";s:170:"Impermeabilización, aislamiento térmico, aislamiento de cubierta y terraza. Nuestro objetivo es reducir los gastos de funcionamiento y preservar el valor a largo plazo.";s:2:"hu";s:150:"Vízszigetelés, hőszigetelés, tető és terasz szigetelése. Célunk az alacsony üzemeltetési költségek és a hosszú távú értékmegőrzés.";}i:16;a:4:{s:3:"key";s:26:"6. Interior Works & Design";s:2:"en";s:26:"6. Interior Works & Design";s:2:"es";s:32:"6. Trabajos interiores y diseño";s:2:"hu";s:28:"6. Belső munkák és design";}i:17;a:4:{s:3:"key";s:136:"Tiling, painting, window and door replacement, bespoke kitchens and bathrooms. Full furnishing and interior design available on request.";s:2:"en";s:136:"Tiling, painting, window and door replacement, bespoke kitchens and bathrooms. Full furnishing and interior design available on request.";s:2:"es";s:156:"Alicatado, pintura, sustitución de ventanas y puertas, cocinas y baños a medida. Amueblamiento completo y diseño de interiores disponible bajo petición.";s:2:"hu";s:144:"Burkolás, festés, nyílászáró csere, egyedi konyha és fürdőszoba kialakítás. Teljes berendezés és belsőépítészet igény szerint.";}i:18;a:4:{s:3:"key";s:17:"7. Exterior Works";s:2:"en";s:17:"7. Exterior Works";s:2:"es";s:22:"7. Trabajos exteriores";s:2:"hu";s:18:"7. Külső munkák";}i:19;a:4:{s:3:"key";s:75:"Facade renovation, terraces, pools, landscaping, fencing and parking areas.";s:2:"en";s:75:"Facade renovation, terraces, pools, landscaping, fencing and parking areas.";s:2:"es";s:84:"Reforma de fachada, terrazas, piscinas, jardinería, vallas y zonas de aparcamiento.";s:2:"hu";s:83:"Homlokzat felújítás, teraszok, medencék, kertészet, kerítések és parkolók.";}i:20;a:4:{s:3:"key";s:39:"8. Project Management & Quality Control";s:2:"en";s:39:"8. Project Management & Quality Control";s:2:"es";s:40:"8. Gestión de obra y control de calidad";s:2:"hu";s:48:"8. Projektmenedzsment és minőség-ellenőrzés";}i:21;a:4:{s:3:"key";s:169:"The entire construction is personally supervised. We provide continuous communication with regular reports and photo documentation, especially for clients living abroad.";s:2:"en";s:169:"The entire construction is personally supervised. We provide continuous communication with regular reports and photo documentation, especially for clients living abroad.";s:2:"es";s:189:"Toda la obra es supervisada personalmente. Ofrecemos comunicación continua con informes periódicos y documentación fotográfica, especialmente para clientes que residen en el extranjero.";s:2:"hu";s:200:"Az egész kivitelezést személyesen felügyeljük. Folyamatos kommunikációt biztosítunk rendszeres jelentésekkel és fotódokumentációval, különösen a külföldön élő ügyfelek számára.";}i:22;a:4:{s:3:"key";s:19:"9. Turnkey Handover";s:2:"en";s:19:"9. Turnkey Handover";s:2:"es";s:24:"9. Entrega llave en mano";s:2:"hu";s:24:"9. Kulcsrakész átadás";}i:23;a:4:{s:3:"key";s:185:"At the end of the works we carry out a technical handover with a checklist and warranty documentation. Our client receives a fully finished property, ready to occupy or let immediately.";s:2:"en";s:185:"At the end of the works we carry out a technical handover with a checklist and warranty documentation. Our client receives a fully finished property, ready to occupy or let immediately.";s:2:"es";s:208:"Al finalizar la obra realizamos una entrega técnica con lista de verificación y documentación de garantía. El cliente recibe un inmueble completamente terminado, listo para ocupar o alquilar de inmediato.";s:2:"hu";s:199:"A munkák végén műszaki átadást tartunk ellenőrző listával és garanciális dokumentációval. Ügyfelünk egy teljesen kész ingatlant kap, amely azonnal beköltözhető vagy bérbe adható.";}i:24;a:4:{s:3:"key";s:158:"Our goal is for our clients to experience the renovation process as stress-free, transparent and safe — while significantly increasing the property''s value.";s:2:"en";s:158:"Our goal is for our clients to experience the renovation process as stress-free, transparent and safe — while significantly increasing the property''s value.";s:2:"es";s:172:"Nuestro objetivo es que los clientes vivan el proceso de reforma de forma tranquila, transparente y segura, mientras se incrementa significativamente el valor del inmueble.";s:2:"hu";s:174:"Célunk, hogy ügyfeleink a felújítási folyamatot stresszmentesen, átláthatóan és biztonságosan éljék meg — miközben az ingatlan értéke jelentősen növekszik.";}i:25;a:4:{s:3:"key";s:221:"If our clients commission only a partial, smaller renovation — for example a full kitchen or bathroom upgrade on the Costa Blanca — we handle the process with the same precision as a full general construction project.";s:2:"en";s:221:"If our clients commission only a partial, smaller renovation — for example a full kitchen or bathroom upgrade on the Costa Blanca — we handle the process with the same precision as a full general construction project.";s:2:"es";s:265:"Si nuestros clientes nos encargan únicamente una reforma parcial o de menor envergadura —por ejemplo, una renovación completa de cocina o baño en la Costa Blanca—, gestionamos el proceso con la misma precisión que una obra de construcción general completa.";s:2:"hu";s:252:"Ha ügyfeleink csak részleges, kisebb felújítást bíznak ránk — például teljes konyha- vagy fürdőszoba-felújítást a Costa Blancán —, a folyamatot ugyanolyan precizitással kezeljük, mint egy teljes általános kivitelezési projektet.";}i:26;a:4:{s:3:"key";s:316:"We assist with design and material selection, then carry out the demolition, mechanical, electrical and tiling works. If required, we can convert a bathroom from a bathtub to a walk-in shower, or vice versa. Old kitchens are transformed with custom-designed, high-quality furniture crafted by our experienced joiner.";s:2:"en";s:316:"We assist with design and material selection, then carry out the demolition, mechanical, electrical and tiling works. If required, we can convert a bathroom from a bathtub to a walk-in shower, or vice versa. Old kitchens are transformed with custom-designed, high-quality furniture crafted by our experienced joiner.";s:2:"es";s:352:"Ayudamos con el diseño y la selección de materiales, y luego ejecutamos los trabajos de demolición, instalaciones mecánicas, eléctricas y alicatado. Si es necesario, podemos transformar un baño con bañera en ducha o viceversa. Las cocinas antiguas se renuevan con muebles a medida de alta calidad fabricados por nuestro experimentado carpintero.";s:2:"hu";s:332:"Segítünk a tervezésben és az anyagválasztásban, majd elvégezzük a bontási, gépészeti, villamos és burkolási munkákat. Szükség esetén egy fürdőszobát kádból zuhanyzóvá alakítunk, vagy fordítva. A régi konyhákat tapasztalt asztalosunk által készített egyedi, magas minőségű bútorokkal újítjuk meg.";}i:27;a:4:{s:3:"key";s:136:"We coordinate and supervise all works throughout, so our clients receive a fast, clean and professional result — with no hidden costs.";s:2:"en";s:136:"We coordinate and supervise all works throughout, so our clients receive a fast, clean and professional result — with no hidden costs.";s:2:"es";s:162:"Coordinamos y supervisamos todos los trabajos en todo momento, para que nuestros clientes obtengan un resultado rápido, limpio y profesional, sin costes ocultos.";s:2:"hu";s:151:"Minden munkát koordinálunk és felügyelünk, így ügyfeleink gyors, tiszta és professzionális eredményt kapnak — rejtett költségek nélkül.";}i:28;a:4:{s:3:"key";s:133:"Whether it''s a single room or the entire property, every project receives the same level of care, precision and personal supervision.";s:2:"en";s:133:"Whether it''s a single room or the entire property, every project receives the same level of care, precision and personal supervision.";s:2:"es";s:133:"Ya sea una sola habitación o todo el inmueble, cada proyecto recibe el mismo nivel de atención, precisión y supervisión personal.";s:2:"hu";s:160:"Akár egyetlen szobáról, akár az egész ingatlanról van szó, minden projekt ugyanolyan szintű gondosságot, precizitást és személyes felügyeletet kap.";}i:29;a:4:{s:3:"key";s:302:"Obtaining permits and required licences is our responsibility. We handle this based on our engineer''s plans, strictly adhering to the town hall''s regulations and requirements. All official documentation is meticulously prepared so you can be confident the project fully complies with local regulations.";s:2:"en";s:302:"Obtaining permits and required licences is our responsibility. We handle this based on our engineer''s plans, strictly adhering to the town hall''s regulations and requirements. All official documentation is meticulously prepared so you can be confident the project fully complies with local regulations.";s:2:"es";s:363:"La obtención de permisos y licencias necesarias es responsabilidad nuestra. Lo gestionamos basándonos en los planos de nuestro ingeniero, respetando estrictamente la normativa y los requisitos del ayuntamiento. Toda la documentación oficial se prepara meticulosamente para que pueda tener la certeza de que el proyecto cumple plenamente con la normativa local.";s:2:"hu";s:349:"Az engedélyek és szükséges licencek megszerzése a mi felelősségünk. Ezt mérnökünk tervei alapján intézzük, szigorúan betartva az önkormányzat előírásait és követelményeit. Minden hivatalos dokumentációt gondosan készítünk el, hogy biztos lehessen abban, hogy a projekt teljes mértékben megfelel a helyi előírásoknak.";}i:30;a:4:{s:3:"key";s:284:"Throughout our work we always strive for transparency and security, so you can entrust your property renovation to us with complete peace of mind. In addition to obtaining permits, we provide continuous professional support to ensure every step meets legal and technical requirements.";s:2:"en";s:284:"Throughout our work we always strive for transparency and security, so you can entrust your property renovation to us with complete peace of mind. In addition to obtaining permits, we provide continuous professional support to ensure every step meets legal and technical requirements.";s:2:"es";s:297:"A lo largo de nuestra labor siempre buscamos la transparencia y la seguridad, para que pueda confiarnos la reforma de su propiedad con total tranquilidad. Además de obtener los permisos, ofrecemos apoyo profesional continuo para garantizar que cada paso cumpla los requisitos legales y técnicos.";s:2:"hu";s:299:"Munkánk során mindig az átláthatóságra és a biztonságra törekszünk, hogy teljes nyugalommal bízhassa ránk ingatlanának felújítását. Az engedélyek megszerzése mellett folyamatos szakmai támogatást nyújtunk, hogy minden lépés megfeleljen a jogi és műszaki követelményeknek.";}i:31;a:4:{s:3:"key";s:123:"All permit procedures are managed by our engineer and handled directly with the town hall — you don''t need to be present.";s:2:"en";s:123:"All permit procedures are managed by our engineer and handled directly with the town hall — you don''t need to be present.";s:2:"es";s:146:"Todos los trámites de permisos son gestionados por nuestro ingeniero y tramitados directamente con el ayuntamiento; no es necesaria su presencia.";s:2:"hu";s:132:"Minden engedélyezési eljárást mérnökünk kezel és közvetlenül az önkormányzattal intéz — Önnek nem kell jelen lennie.";}i:32;a:4:{s:3:"key";s:116:"Our project reference gallery is coming soon. Please contact us directly to learn more about our completed projects.";s:2:"en";s:116:"Our project reference gallery is coming soon. Please contact us directly to learn more about our completed projects.";s:2:"es";s:192:"Próximamente estará disponible nuestra galería de proyectos de referencia. Póngase en contacto con nosotros directamente para obtener más información sobre nuestros proyectos realizados.";s:2:"hu";s:163:"Projekt-referencia galériánk hamarosan elérhető lesz. Kérjük, lépjen kapcsolatba velünk közvetlenül befejezett projektjeinkről való tájékozódáshoz.";}i:33;a:4:{s:3:"key";s:102:"Contact us for a free consultation and tailored quote for your renovation project on the Costa Blanca.";s:2:"en";s:102:"Contact us for a free consultation and tailored quote for your renovation project on the Costa Blanca.";s:2:"es";s:126:"Contáctenos para obtener una consulta gratuita y un presupuesto personalizado para su proyecto de reforma en la Costa Blanca.";s:2:"hu";s:150:"Lépjen kapcsolatba velünk ingyenes tanácsadásért és személyre szabott árajánlatért Costa Blancán megvalósuló felújítási projektjéhez.";}}', '2095104891');
