INSERT INTO "page_sections" ("id", "page", "section_key", "extra", "sort_order", "is_active", "created_at", "updated_at", "title", "subtitle", "content") VALUES ('1', 'home', 'hero', '{"hero_image":null,"primary_cta":{"label":{"en":"Explore Properties","es":"Explorar Propiedades","hu":"Ingatlanok B\u00f6ng\u00e9sz\u00e9se"},"route":"properties.index"},"secondary_cta":{"label":{"en":"Talk To Our Team","es":"Hablar Con Nuestro Equipo","hu":"Kapcsolat a Csapattal"},"route":"contact"},"pillars":[{"label":{"en":"Our Mission","es":"Nuestra Misi\u00f3n","hu":"K\u00fcldet\u00e9s\u00fcnk"},"body":{"en":"Fully aware of our responsibility, we help you find or refurbish your home in Spain with personalized services.","es":"Plenamente conscientes de nuestra responsabilidad, te ayudamos a encontrar o reformar tu hogar en Espa\u00f1a.","hu":"Felel\u0151ss\u00e9g\u00fcnk teljes tudat\u00e1ban seg\u00edt\u00fcnk megtal\u00e1lni vagy fel\u00faj\u00edtani otthon\u00e1t Spanyolorsz\u00e1gban."}},{"label":{"en":"Our Vision","es":"Nuestra Visi\u00f3n","hu":"J\u00f6v\u0151k\u00e9p\u00fcnk"},"body":{"en":"Through innovation to achieve a dominant position on the market. Providing the best services to our Customers.","es":"A trav\u00e9s de la innovaci\u00f3n para lograr una posici\u00f3n dominante en el mercado. Proporcionando los mejores servicios.","hu":"Innov\u00e1ci\u00f3 r\u00e9v\u00e9n vezet\u0151 poz\u00edci\u00f3 el\u00e9r\u00e9se a piacon, a legjobb szolg\u00e1ltat\u00e1sokkal."}},{"label":{"en":"Are You Ready?","es":"\u00bfEst\u00e1s Listo?","hu":"K\u00e9szen \u00c1ll?"},"body":{"en":"To start your life in Spain, whether in a city on the peninsula, or in Ibiza or one of the other Spanish islands.","es":"Para comenzar tu vida en Espa\u00f1a, ya sea en la pen\u00ednsula o en una de las islas espa\u00f1olas.","hu":"Hogy megkezdje \u00e9let\u00e9t Spanyolorsz\u00e1gban, ak\u00e1r a f\u00e9lszigeten, ak\u00e1r a szigeteken."}}]}', '1', '1', '2026-05-24 21:28:00', '2026-05-24 21:28:00', '{"en":"Welcome to DOBERO","es":"Bienvenido a DOBERO","hu":"Üdvözöljük a DOBERO-nál"}', '{"en":"The DOBERO team is who realize your spanish home! The key to your spanish home is here with us! Come and pick it up!","es":"¡El equipo DOBERO es quien realiza tu hogar español! ¡La llave de tu hogar español está aquí con nosotros!","hu":"A DOBERO csapata valósítja meg az ön spanyol otthonát! A kulcs az ön spanyol otthonához itt van nálunk!"}', '{"en":"Fully aware of our responsibility, we help you find or refurbish your home in Spain with personalized services.","es":"Plenamente conscientes de nuestra responsabilidad, te ayudamos a encontrar o reformar tu hogar en España con servicios personalizados.","hu":"Felelősségünk teljes tudatában segítünk megtalálni vagy felújítani otthonát Spanyolországban személyre szabott szolgáltatásokkal."}');
