INSERT INTO "page_sections" ("id", "page", "section_key", "extra", "sort_order", "is_active", "created_at", "updated_at", "title", "subtitle", "content") VALUES ('3', 'home', 'expertise', '{"button_label":{"en":"Learn More","es":"Saber M\u00e1s","hu":"Tudjon Meg T\u00f6bbet"},"button_url":"\/about-us"}', '3', '1', '2026-05-24 21:28:00', '2026-05-25 13:44:17', '{"en":"Real Estate Expertise For Over 15 Years","es":"Experiencia Inmobiliaria Por Más de 15 Años","hu":"Több Mint 15 Éves Ingatlanpiaci Tapasztalat"}', '{"en":null}', '{"en":"We combine estate agency, relocation consulting, building pathology, financing guidance, and local market intelligence. That means fewer surprises and faster decisions for local and international buyers alike.","es":"Combinamos agencia inmobiliaria, consultoría de reubicación, patología de edificios, orientación financiera e inteligencia local de mercado.","hu":"Ötvözzük az ingatlanközvetítést, a költözési tanácsadást, az épületpatológiát és a finanszírozási útmutatást."}');
