INSERT INTO "page_sections" ("id", "page", "section_key", "extra", "sort_order", "is_active", "created_at", "updated_at", "title", "subtitle", "content") VALUES ('5', 'home', 'investment', '{"button_label":{"en":"View Properties","es":"Ver Propiedades","hu":"Ingatlanok Megtekint\u00e9se"},"button_url":"\/properties","images":[],"bullets":[{"en":"Complete Documentation","es":"Documentaci\u00f3n Completa","hu":"Teljes Dokument\u00e1ci\u00f3"},{"en":"Transferring Utility Meters","es":"Transferencia de Suministros","hu":"K\u00f6zm\u0171\u00f3r\u00e1k \u00c1t\u00edr\u00e1sa"},{"en":"Redesigning Property","es":"Redise\u00f1o de la Propiedad","hu":"Ingatlan \u00dajratervez\u00e9se"},{"en":"Obtain All The Licences","es":"Obtener Todas las Licencias","hu":"Minden Enged\u00e9ly Beszerz\u00e9se"},{"en":"Refurbishment","es":"Reforma","hu":"Fel\u00faj\u00edt\u00e1s"}]}', '5', '1', '2026-05-24 21:28:00', '2026-05-25 13:22:33', '{"en":"You Can Find Your Perfect Investment","es":"Puede Encontrar Su Inversión Perfecta","hu":"Megtalálhatja Tökéletes Befektetését"}', '{"en":null}', '{"en":"Browse a portfolio of contemporary apartments, sea-view villas, and value-add properties selected for location quality, resale potential, and renovation upside.","es":"Explore una cartera de apartamentos contemporáneos, villas con vistas al mar y propiedades con potencial de revalorización.","hu":"Fedezze fel a kortárs lakások, tengeri panorámás villák és értéknövelő ingatlanok portfólióját."}');
INSERT INTO "page_sections" ("id", "page", "section_key", "extra", "sort_order", "is_active", "created_at", "updated_at", "title", "subtitle", "content") VALUES ('6', 'home', 'contact', NULL, '6', '1', '2026-05-24 21:28:00', '2026-05-24 21:28:00', '{"en":"Please Write To Us","es":"Por Favor Escríbanos","hu":"Kérjük Írjon Nekünk"}', '{"en":null}', '{"en":"If you are looking for a property or if you need any refurbishment!\n\nOr — if you want to be your own boss, build your career with us. As a marketing worker you can post our properties, represent us in your country, and receive a 50% commission for every property sold.","es":"¡Si está buscando una propiedad o si necesita alguna reforma!\n\nO — si quiere ser su propio jefe, construya su carrera con nosotros.","hu":"Ha ingatlant keres vagy felújításra van szüksége!\n\nVagy ha saját főnöke szeretne lenni, építse karrierjét velünk."}');
