INSERT INTO "page_sections" ("id", "page", "section_key", "extra", "sort_order", "is_active", "created_at", "updated_at", "title", "subtitle", "content") VALUES ('12', 'about', 'intro', '{"column_two":{"en":"We understand that moving to a new country is a huge decision. Our multilingual team creates personalized plans around each client\u2019s goals.","es":"Entendemos que mudarse a un nuevo pa\u00eds es una gran decisi\u00f3n. Nuestro equipo multiling\u00fce crea planes personalizados.","hu":"Meg\u00e9rtj\u00fck, hogy \u00faj orsz\u00e1gba k\u00f6lt\u00f6zni nagy d\u00f6nt\u00e9s. T\u00f6bbnyelv\u0171 csapatunk szem\u00e9lyre szabott terveket k\u00e9sz\u00edt."}}', '2', '1', '2026-05-24 21:28:00', '2026-05-24 21:28:00', '{"en":"WE CREATE NEW LIFES AND NEW HOMES ON THE COSTA BLANCA!","es":"¡CREAMOS NUEVAS VIDAS Y NUEVOS HOGARES EN LA COSTA BLANCA!","hu":"ÚJ ÉLETEKET ÉS ÚJ OTTHONOKAT TEREMTÜNK A COSTA BLANCÁN!"}', '{"en":null}', '{"en":"Our logo symbolizes enduring strength and deep roots. Our experience ensures we are a steadfast partner while you create your new life and home in Spain.","es":"Nuestro logo simboliza fortaleza duradera y raíces profundas. Nuestra experiencia garantiza que seremos un socio firme en su nueva vida en España.","hu":"Logónk tartós erőt és mély gyökereket jelképez. Tapasztalatunk biztosítja, hogy megbízható partnerek legyünk új spanyol életében."}');
INSERT INTO "page_sections" ("id", "page", "section_key", "extra", "sort_order", "is_active", "created_at", "updated_at", "title", "subtitle", "content") VALUES ('13', 'about', 'team', NULL, '4', '1', '2026-05-24 21:28:00', '2026-05-25 13:22:33', '{"en":"Meet our Team","es":"Conoce a Nuestro Equipo","hu":"Ismerje Meg Csapatunkat"}', '{"en":"Experienced specialists in real estate, law, architecture, construction, and client services.","es":"Especialistas en bienes raíces, derecho, arquitectura, construcción y atención al cliente.","hu":"Tapasztalt szakemberek az ingatlan, jogi, építészeti, kivitelezési és ügyfélszolgálati területen."}', '{"en":null}');
