INSERT INTO "pages" ("id", "key", "slug", "title", "body", "meta_title", "meta_description", "is_published", "published_at", "deletable", "sort_order", "created_at", "updated_at") VALUES ('1', 'about', '{"en":"about-us","es":"sobre-nosotros","hu":"rolunk"}', '{"en":"About Us","es":"Sobre Nosotros","hu":"Rólunk"}', '{"en":"<p>DOBERO HOME CREATOR supports international buyers with property sourcing, relocation guidance, construction planning, and trusted local insight across Spain.</p>","es":"<p>DOBERO HOME CREATOR apoya a compradores internacionales con búsqueda de propiedades, asesoramiento en reubicación, planificación de construcción y experiencia local.</p>","hu":"<p>A DOBERO HOME CREATOR támogatja a nemzetközi vásárlókat ingatlankereséssel, költözési tanácsadással és helyi szakértelemmel Spanyolországban.</p>"}', '{"en":"About DOBERO","es":"Sobre DOBERO","hu":"A DOBERO-ról"}', '{"en":"Learn about DOBERO HOME CREATOR and its real estate, relocation, and construction services in Spain.","es":"Conozca DOBERO HOME CREATOR y sus servicios inmobiliarios, de reubicación y construcción en España.","hu":"Ismerje meg a DOBERO HOME CREATOR ingatlanos, költözési és építési szolgáltatásait Spanyolországban."}', '1', '2026-05-24 21:28:00', '0', '1', '2026-05-24 21:28:00', '2026-05-25 13:51:47');
INSERT INTO "pages" ("id", "key", "slug", "title", "body", "meta_title", "meta_description", "is_published", "published_at", "deletable", "sort_order", "created_at", "updated_at") VALUES ('2', 'contact', '{"en":"contact","es":"contacto","hu":"kapcsolat"}', '{"en":"Contact","es":"Contacto","hu":"Kapcsolat"}', '{"en":"<p>Tell us what you are searching for and our team will prepare the next best steps.</p>","es":"<p>Cuéntenos qué está buscando y nuestro equipo preparará los siguientes pasos.</p>","hu":"<p>Ossza meg velünk céljait, és csapatunk előkészíti a következő lépéseket.</p>"}', '{"en":"Contact DOBERO","es":"Contactar con DOBERO","hu":"Kapcsolat a DOBERO-val"}', '{"en":"Get in touch with DOBERO HOME CREATOR.","es":"Póngase en contacto con DOBERO HOME CREATOR.","hu":"Vegye fel a kapcsolatot a DOBERO HOME CREATOR csapatával."}', '1', '2026-05-24 21:28:00', '0', '2', '2026-05-24 21:28:00', '2026-05-24 21:28:00');
INSERT INTO "pages" ("id", "key", "slug", "title", "body", "meta_title", "meta_description", "is_published", "published_at", "deletable", "sort_order", "created_at", "updated_at") VALUES ('3', 'relocation', '{"en":"relocation","es":"reubicacion","hu":"koltozes"}', '{"en":"Relocation","es":"Reubicación","hu":"Költözés"}', '{"en":"<p>Move to Spain with confidence through practical support for residency, utilities, schools, and settling in.</p>","es":"<p>Múdese a España con confianza con apoyo práctico para residencia, suministros, colegios y adaptación.</p>","hu":"<p>Költözzön Spanyolországba magabiztosan gyakorlati támogatással a letelepedés minden szakaszában.</p>"}', '{"en":"Relocation Services","es":"Servicios de Reubicación","hu":"Költözési Szolgáltatások"}', '{"en":"Relocation support for moving to Spain.","es":"Apoyo de reubicación para mudarse a España.","hu":"Költözési támogatás Spanyolországba költözéshez."}', '1', '2026-05-24 21:28:00', '0', '3', '2026-05-24 21:28:00', '2026-05-24 21:28:00');
INSERT INTO "pages" ("id", "key", "slug", "title", "body", "meta_title", "meta_description", "is_published", "published_at", "deletable", "sort_order", "created_at", "updated_at") VALUES ('4', 'construction', '{"en":"construction","es":"construccion","hu":"epitkezes"}', '{"en":"Construction","es":"Construcción","hu":"Építkezés"}', '{"en":"<p>From pathology reviews to refurbishment delivery, we coordinate trusted professionals for your property project.</p>","es":"<p>Desde revisiones técnicas hasta la entrega de reformas, coordinamos profesionales de confianza para su proyecto.</p>","hu":"<p>A műszaki felméréstől a felújítás átadásáig megbízható szakembereket koordinálunk projektjéhez.</p>"}', '{"en":"Construction Services","es":"Servicios de Construcción","hu":"Építési Szolgáltatások"}', '{"en":"Construction and refurbishment support for Spanish properties.","es":"Apoyo en construcción y reformas para propiedades en España.","hu":"Építési és felújítási támogatás spanyol ingatlanokhoz."}', '1', '2026-05-24 21:28:00', '0', '4', '2026-05-24 21:28:00', '2026-05-24 21:28:00');
