INSERT INTO "site_settings" ("id", "key", "type", "created_at", "updated_at", "is_translatable", "value") VALUES ('2', 'site_description', 'textarea', '2026-05-24 21:28:00', '2026-05-24 21:28:00', '1', '{"en":"The DOBERO team is who realize your spanish home! The key to your spanish home is here with us!","es":"¡El equipo DOBERO es quien realiza tu hogar español! ¡La llave de tu hogar español está aquí con nosotros!","hu":"A DOBERO csapata valósítja meg az ön spanyol otthonát! A kulcs az ön spanyol otthonához itt van nálunk!"}');
INSERT INTO "site_settings" ("id", "key", "type", "created_at", "updated_at", "is_translatable", "value") VALUES ('3', 'footer_about', 'textarea', '2026-05-24 21:28:00', '2026-05-24 21:28:00', '1', '{"en":"DOBERO HOME CREATOR combines property search, relocation support, construction guidance, and local expertise to help international buyers invest with confidence on the Costa Blanca.","es":"DOBERO HOME CREATOR combina búsqueda de propiedades, apoyo para la reubicación, orientación en construcción y experiencia local para ayudar a compradores internacionales a invertir con confianza en la Costa Blanca.","hu":"A DOBERO HOME CREATOR ingatlankeresést, költözési támogatást, építési útmutatást és helyi szakértelmet kombinál, hogy a nemzetközi vásárlók magabiztosan fektessenek be a Costa Blancán."}');
INSERT INTO "site_settings" ("id", "key", "type", "created_at", "updated_at", "is_translatable", "value") VALUES ('4', 'address', 'text', '2026-05-24 21:28:00', '2026-05-24 21:28:00', '0', '{"en":"Costa Blanca, Spain"}');
