INSERT INTO "team_members" ("id", "name", "photo", "sort_order", "is_active", "created_at", "updated_at", "role", "bio") VALUES ('1', 'János Németh', '/images/defaults/team-janos.jpg', '1', '1', '2026-05-24 21:28:00', '2026-05-25 13:22:33', '{"en":"CEO","es":"CEO","hu":"Vezérigazgató"}', '{"en":"János leads DOBERO with decades of cross-border property consulting and investment strategy experience on the Costa Blanca.","es":"János lidera DOBERO con décadas de experiencia en consultoría de propiedades transfronterizas y estrategia de inversión en la Costa Blanca.","hu":"János évtizedes határokon átnyúló ingatlan-tanácsadási és befektetési stratégiai tapasztalattal vezeti a DOBERO-t a Costa Blancán."}');
INSERT INTO "team_members" ("id", "name", "photo", "sort_order", "is_active", "created_at", "updated_at", "role", "bio") VALUES ('2', 'Keith Bailey', '/images/defaults/team-1.jpg', '2', '1', '2026-05-24 21:28:00', '2026-05-24 21:28:00', '{"en":"CEO","es":"CEO","hu":"Vezérigazgató"}', '{"en":"Keith drives business development, partner relations, and client acquisition across the international buyer market.","es":"Keith impulsa el desarrollo de negocios, las relaciones con socios y la adquisición de clientes en el mercado internacional.","hu":"Keith vezeti az üzletfejlesztést, a partnerkapcsolatokat és az ügyfélszerzést a nemzetközi vevői piacon."}');
INSERT INTO "team_members" ("id", "name", "photo", "sort_order", "is_active", "created_at", "updated_at", "role", "bio") VALUES ('3', 'Danielle Murray', '/images/defaults/team-2.jpg', '3', '1', '2026-05-24 21:28:00', '2026-05-24 21:28:00', '{"en":"Manager","es":"Directora","hu":"Menedzser"}', '{"en":"Danielle coordinates client communication, viewings, relocation logistics, and post-sale property management.","es":"Danielle coordina la comunicación con clientes, visitas, logística de reubicación y gestión de propiedades post-venta.","hu":"Danielle koordinálja az ügyfelekkel való kommunikációt, a megtekintéseket, a költözési logisztikát és az értékesítés utáni ingatlankezelést."}');
INSERT INTO "team_members" ("id", "name", "photo", "sort_order", "is_active", "created_at", "updated_at", "role", "bio") VALUES ('4', 'Thomas Stevens', '/images/defaults/team-3.jpg', '4', '1', '2026-05-24 21:28:00', '2026-05-24 21:28:00', '{"en":"Manager","es":"Director","hu":"Menedzser"}', '{"en":"Thomas sources high-potential homes across the Costa Blanca and negotiates deals suited to lifestyle and investment goals.","es":"Thomas busca hogares de alto potencial en toda la Costa Blanca y negocia acuerdos adaptados a objetivos de estilo de vida e inversión.","hu":"Thomas nagy potenciálú otthonokat keres a Costa Blancán és tárgyalja meg az életstílus- és befektetési célokhoz igazított megállapodásokat."}');
INSERT INTO "team_members" ("id", "name", "photo", "sort_order", "is_active", "created_at", "updated_at", "role", "bio") VALUES ('5', 'Nydia Olaizola Sentí', '/images/defaults/team-nydia.jpg', '2', '1', '2026-05-25 13:22:33', '2026-05-25 13:22:33', '{"en":"Lawyer","es":"Abogada","hu":"Ügyvéd"}', '{"en":"Nydia handles all legal aspects of property acquisition and conveyancing, ensuring a smooth and legally sound transaction for every client.","es":"Nydia se encarga de todos los aspectos legales de la adquisición de propiedades, garantizando una transacción segura para cada cliente.","hu":"Nydia kezeli az ingatlanvásárlás összes jogi aspektusát, biztosítva a zökkenőmentes és jogilag megalapozott tranzakciókat."}');
INSERT INTO "team_members" ("id", "name", "photo", "sort_order", "is_active", "created_at", "updated_at", "role", "bio") VALUES ('6', 'Jovi Tortosa', '/images/defaults/team-jovi.jpg', '3', '1', '2026-05-25 13:22:33', '2026-05-25 13:22:33', '{"en":"Architect","es":"Arquitecto","hu":"Építész"}', '{"en":"Jovi designs and oversees construction projects, bringing creative vision and technical expertise to every build on the Costa Blanca.","es":"Jovi diseña y supervisa proyectos de construcción, aportando visión creativa y experiencia técnica a cada obra en la Costa Blanca.","hu":"Jovi tervez és felügyel kivitelezési projekteket, kreatív vízióval és műszaki szakértelemmel."}');
INSERT INTO "team_members" ("id", "name", "photo", "sort_order", "is_active", "created_at", "updated_at", "role", "bio") VALUES ('7', 'Daria Artemyeva', '/images/defaults/team-daria.jpg', '4', '1', '2026-05-25 13:22:33', '2026-05-25 13:22:33', '{"en":"Interior Architect","es":"Arquitecta de Interiores","hu":"Belsőépítész"}', '{"en":"Daria transforms spaces into elegant, functional homes, balancing aesthetics and practicality for international clients.","es":"Daria transforma espacios en hogares elegantes y funcionales, equilibrando estética y practicidad para clientes internacionales.","hu":"Daria elegáns, funkcionális otthonokká alakítja a tereket, esztétikát és praktikusságot ötvözve."}');
INSERT INTO "team_members" ("id", "name", "photo", "sort_order", "is_active", "created_at", "updated_at", "role", "bio") VALUES ('8', 'Sara Travieso Garcia', '/images/defaults/team-sara.jpg', '5', '1', '2026-05-25 13:22:33', '2026-05-25 13:22:33', '{"en":"Real Estate Agent","es":"Agente Inmobiliaria","hu":"Ingatlanügynök"}', '{"en":"Sara guides buyers through property searches, viewings, and negotiations, matching clients to their ideal home on the Costa Blanca.","es":"Sara acompaña a los compradores en la búsqueda de propiedades, visitas y negociaciones, encontrando el hogar ideal en la Costa Blanca.","hu":"Sara segíti a vevőket az ingatlankeresésben, megtekintésekben és tárgyalásokban, megtalálva az ideális otthont."}');
INSERT INTO "team_members" ("id", "name", "photo", "sort_order", "is_active", "created_at", "updated_at", "role", "bio") VALUES ('9', 'Michael Ramirez Da Silva', '/images/defaults/team-michael.jpg', '6', '1', '2026-05-25 13:22:33', '2026-05-25 13:22:33', '{"en":"Solar Systems Specialist","es":"Especialista en Energía Solar","hu":"Napenergia-rendszer Szakértő"}', '{"en":"Michael designs and installs solar energy systems, helping property owners reduce costs and embrace sustainable living.","es":"Michael diseña e instala sistemas de energía solar, ayudando a los propietarios a reducir costes y apostar por un estilo de vida sostenible.","hu":"Michael napenergia-rendszereket tervez és telepít, segítve az ingatlan-tulajdonosokat a fenntartható életmód megvalósításában."}');
INSERT INTO "team_members" ("id", "name", "photo", "sort_order", "is_active", "created_at", "updated_at", "role", "bio") VALUES ('10', 'Jonathan', '/images/defaults/team-jonathan.jpg', '7', '1', '2026-05-25 13:22:33', '2026-05-25 13:22:33', '{"en":"Vertical Works Specialist","es":"Especialista en Trabajos Verticales","hu":"Magassági Munkák Szakértője"}', '{"en":"Jonathan specialises in vertical access and facade works, maintaining and renovating building exteriors with safety and precision.","es":"Jonathan se especializa en trabajos de acceso vertical y fachadas, manteniendo y renovando exteriores con seguridad y precisión.","hu":"Jonathan a függőleges munkák és homlokzati munkák specialistája, biztonságosan és pontosan végzi a karbantartást és felújítást."}');
INSERT INTO "team_members" ("id", "name", "photo", "sort_order", "is_active", "created_at", "updated_at", "role", "bio") VALUES ('11', 'Héctor Soler Alonso', '/images/defaults/team-hector.jpg', '8', '1', '2026-05-25 13:22:33', '2026-05-25 13:22:33', '{"en":"Electrical & SMART Systems","es":"Instalaciones Eléctricas y Sistemas SMART","hu":"Elektromos és Okos Rendszerek"}', '{"en":"Héctor oversees all electrical installations and smart-home integrations, ensuring modern, energy-efficient solutions for every property.","es":"Héctor supervisa todas las instalaciones eléctricas e integraciones de hogar inteligente, asegurando soluciones modernas y eficientes.","hu":"Héctor felügyeli az összes elektromos szerelést és okosotthon-integrációt, modern és energiahatékony megoldásokat biztosítva."}');
INSERT INTO "team_members" ("id", "name", "photo", "sort_order", "is_active", "created_at", "updated_at", "role", "bio") VALUES ('12', 'Ricardo Alejo', '/images/defaults/team-ricardo.jpg', '9', '1', '2026-05-25 13:22:33', '2026-05-25 13:22:33', '{"en":"Drywall & Painting","es":"Pladur y Pintura","hu":"Szárazépítés és Festés"}', '{"en":"Ricardo delivers high-quality drywall and painting finishes, transforming interiors to a professional standard on every project.","es":"Ricardo realiza trabajos de alta calidad en pladur y pintura, transformando interiores con acabados profesionales en cada proyecto.","hu":"Ricardo kiváló minőségű szárazépítési és festési munkákat végez, professzionális belső tér-kialakítással."}');
INSERT INTO "team_members" ("id", "name", "photo", "sort_order", "is_active", "created_at", "updated_at", "role", "bio") VALUES ('13', 'Julián Vico Rentero', '/images/defaults/team-julian.jpg', '10', '1', '2026-05-25 13:22:33', '2026-05-25 13:22:33', '{"en":"Court Expert","es":"Perito Judicial","hu":"Igazságügyi Szakértő"}', '{"en":"Julián provides expert appraisals and technical reports for legal proceedings, protecting clients in complex property disputes.","es":"Julián proporciona peritajes y dictámenes técnicos para procedimientos judiciales, protegiendo a los clientes en disputas de propiedad.","hu":"Julián szakvéleményeket és műszaki jelentéseket készít jogi eljárásokhoz, megvédve az ügyfeleket az ingatlanvitákban."}');
INSERT INTO "team_members" ("id", "name", "photo", "sort_order", "is_active", "created_at", "updated_at", "role", "bio") VALUES ('14', 'Pedro', '/images/defaults/team-pedro.jpg', '11', '1', '2026-05-25 13:22:33', '2026-05-25 13:22:33', '{"en":"Alarm Systems Specialist","es":"Especialista en Sistemas de Alarma","hu":"Riasztórendszer Szakértő"}', '{"en":"Pedro installs and maintains alarm and security systems, giving property owners peace of mind with reliable protection.","es":"Pedro instala y mantiene sistemas de alarma y seguridad, ofreciendo tranquilidad a los propietarios con una protección fiable.","hu":"Pedro riasztó- és biztonsági rendszereket telepít és tart karban, megbízható védelmet biztosítva az ingatlan-tulajdonosoknak."}');
INSERT INTO "team_members" ("id", "name", "photo", "sort_order", "is_active", "created_at", "updated_at", "role", "bio") VALUES ('15', 'Antonio Ortigosa', '/images/defaults/team-antonio.jpg', '12', '1', '2026-05-25 13:22:33', '2026-05-25 13:22:33', '{"en":"Aluminum Carpentry","es":"Carpintería de Aluminio","hu":"Alumínium Asztalos"}', '{"en":"Antonio fabricates and installs aluminium windows, doors, and facades, combining durability and contemporary design.","es":"Antonio fabrica e instala ventanas, puertas y fachadas de aluminio, combinando durabilidad y diseño contemporáneo.","hu":"Antonio alumínium nyílászárókat, ajtókat és homlokzatokat gyárt és szerel, tartósságot és modern designt ötvözve."}');
