INSERT INTO "testimonials" ("id", "author_name", "author_company", "author_photo", "sort_order", "is_active", "created_at", "updated_at", "content", "author_role") VALUES ('1', 'Roy Bennett', 'United Kingdom', '/images/defaults/testimonial-1.jpg', '1', '1', '2026-05-24 21:28:00', '2026-05-24 21:28:00', '{"en":"Really good service. We can''t understand how we''ve been living without DOBERO. They handled our NIE, bank account, and found us the perfect flat in Alicante.","es":"Realmente buen servicio. No podemos entender cómo hemos vivido sin DOBERO. Gestionaron nuestro NIE, cuenta bancaria y nos encontraron el piso perfecto en Alicante.","hu":"Igazán jó szolgáltatás. Nem értjük, hogyan éltünk DOBERO nélkül. Intézték a NIE-nkat, a bankszámlánkat, és megtalálták nekünk a tökéletes lakást Alicantéban."}', '{"en":"Marketing Manager","es":"Directora de Marketing","hu":"Marketing Menedzser"}');
INSERT INTO "testimonials" ("id", "author_name", "author_company", "author_photo", "sort_order", "is_active", "created_at", "updated_at", "content", "author_role") VALUES ('2', 'Kenneth Sandoval', 'United States', '/images/defaults/testimonial-2.jpg', '2', '1', '2026-05-24 21:28:00', '2026-05-24 21:28:00', '{"en":"Great work on finding our investment property. I like DOBERO more and more each day because it makes my life easier and a lot more profitable.","es":"Excelente trabajo para encontrar nuestra propiedad de inversión. Me gusta DOBERO cada día más porque hace mi vida más fácil y mucho más rentable.","hu":"Kiváló munka a befektetési ingatlanunk megtalálásában. Napról napra jobban szeretem a DOBERO-t, mert könnyebbé és sokkal jövedelmezőbbé teszi az életemet."}', '{"en":"Investor","es":"Inversor","hu":"Befektető"}');
INSERT INTO "testimonials" ("id", "author_name", "author_company", "author_photo", "sort_order", "is_active", "created_at", "updated_at", "content", "author_role") VALUES ('3', 'Kathleen Peterson', 'Germany', '/images/defaults/testimonial-3.jpg', '3', '1', '2026-05-24 21:28:00', '2026-05-24 21:28:00', '{"en":"DOBERO is the best real estate partner I have ever worked with. I strongly recommend them to everyone interested in buying property in Spain successfully.","es":"DOBERO es el mejor socio inmobiliario con el que he trabajado. Los recomiendo encarecidamente a todos los interesados en comprar una propiedad en España con éxito.","hu":"A DOBERO a legjobb ingatlan partner, akivel valaha dolgoztam. Erősen ajánlom mindenki számára, aki sikeresen szeretne ingatlant vásárolni Spanyolországban."}', '{"en":"Sales Manager","es":"Directora de Ventas","hu":"Értékesítési Menedzser"}');
