CREATE TABLE "blog_posts" ("id" integer primary key autoincrement not null, "slug" varchar not null, "image" varchar, "category" varchar, "author" varchar, "published_at" datetime, "is_published" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, "title" text, "excerpt" text, "content" text);


CREATE TABLE "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));


CREATE TABLE "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));


CREATE TABLE "contact_inquiries" ("id" integer primary key autoincrement not null, "inquiry_type" varchar, "first_name" varchar not null, "last_name" varchar not null, "email" varchar not null, "phone" varchar, "message" text, "property_id" integer, "min_price" numeric, "max_price" numeric, "bedrooms" integer, "bathrooms" integer, "is_read" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("property_id") references "properties"("id") on delete set null);


CREATE TABLE "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" varchar not null, "queue" varchar not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);


CREATE TABLE "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));


CREATE TABLE "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);


CREATE TABLE "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);


CREATE TABLE "nav_items" ("id" integer primary key autoincrement not null, "parent_id" integer, "label" text not null, "url" text not null, "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "opens_in_new_tab" tinyint(1) not null default '0', "location" varchar not null default 'primary', "created_at" datetime, "updated_at" datetime, foreign key("parent_id") references "nav_items"("id") on delete cascade);


CREATE TABLE "page_sections" ("id" integer primary key autoincrement not null, "page" varchar not null, "section_key" varchar not null, "extra" text, "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, "title" text, "subtitle" text, "content" text);


CREATE TABLE "pages" ("id" integer primary key autoincrement not null, "key" varchar not null, "slug" text not null, "title" text not null, "body" text not null, "meta_title" text, "meta_description" text, "is_published" tinyint(1) not null default '0', "published_at" datetime, "deletable" tinyint(1) not null default '1', "sort_order" integer not null default '0', "created_at" datetime, "updated_at" datetime);


CREATE TABLE "passkeys" ("id" integer primary key autoincrement not null, "user_id" integer not null, "name" varchar not null, "credential_id" varchar not null, "credential" text not null, "last_used_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);


CREATE TABLE "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));


CREATE TABLE "personal_access_tokens" ("id" integer primary key autoincrement not null, "tokenable_type" varchar not null, "tokenable_id" integer not null, "name" text not null, "token" varchar not null, "abilities" text, "last_used_at" datetime, "expires_at" datetime, "created_at" datetime, "updated_at" datetime);


CREATE TABLE "properties" ("id" integer primary key autoincrement not null, "slug" varchar not null, "address" varchar not null, "city" varchar not null, "state_country" varchar not null, "postal_code" varchar not null, "price" numeric not null, "currency" varchar not null default 'EUR', "property_type" varchar check ("property_type" in ('house', 'flat', 'villa', 'apartment', 'commercial', 'land')) not null, "status" varchar check ("status" in ('for_sale', 'for_rent', 'sold', 'rented')) not null default 'for_sale', "bedrooms" integer not null default '0', "bathrooms" integer not null default '0', "sqm" numeric not null default '0', "images" text, "is_featured" tinyint(1) not null default '0', "property_id_ref" varchar, "created_at" datetime, "updated_at" datetime, "title" text, "description" text);


CREATE TABLE "property_reviews" ("id" integer primary key autoincrement not null, "property_id" integer not null, "title" varchar not null, "rating" integer not null, "review" text not null, "author_name" varchar not null, "author_email" varchar not null, "is_approved" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("property_id") references "properties"("id") on delete cascade);


CREATE TABLE "services" ("id" integer primary key autoincrement not null, "image" varchar, "icon" varchar, "category" varchar, "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, "title" text, "description" text);


CREATE TABLE "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));


CREATE TABLE "site_settings" ("id" integer primary key autoincrement not null, "key" varchar not null, "type" varchar check ("type" in ('text', 'textarea', 'image', 'boolean', 'json')) not null default 'text', "created_at" datetime, "updated_at" datetime, "is_translatable" tinyint(1) not null default '0', "value" text);


CREATE TABLE "team_invitations" ("id" integer primary key autoincrement not null, "team_id" integer not null, "email" varchar not null, "role" varchar, "created_at" datetime, "updated_at" datetime, foreign key("team_id") references "teams"("id") on delete cascade);


CREATE TABLE "team_members" ("id" integer primary key autoincrement not null, "name" varchar not null, "photo" varchar, "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, "role" text, "bio" text);


CREATE TABLE "team_user" ("id" integer primary key autoincrement not null, "team_id" integer not null, "user_id" integer not null, "role" varchar, "created_at" datetime, "updated_at" datetime);


CREATE TABLE "teams" ("id" integer primary key autoincrement not null, "user_id" integer not null, "name" varchar not null, "personal_team" tinyint(1) not null, "created_at" datetime, "updated_at" datetime);


CREATE TABLE "testimonials" ("id" integer primary key autoincrement not null, "author_name" varchar not null, "author_company" varchar, "author_photo" varchar, "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, "content" text, "author_role" text);


CREATE TABLE "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "current_team_id" integer, "profile_photo_path" varchar, "created_at" datetime, "updated_at" datetime, "two_factor_secret" text, "two_factor_recovery_codes" text, "two_factor_confirmed_at" datetime);


